-- V12: EU food additives database from European Commission FIP
-- Source: https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search
-- Translated to Lithuanian using Claude Sonnet

CREATE TABLE aggregate.eu_additives (
    id BIGINT PRIMARY KEY,
    e_number TEXT,
    e_number_display TEXT,
    e_number_sort INT,

    display_name_en TEXT NOT NULL,
    display_name_lt TEXT,
    identifying_name_en TEXT,
    identifying_name_lt TEXT,

    synonyms_en TEXT[],
    synonyms_lt TEXT[],
    ins_number TEXT,
    is_group BOOLEAN DEFAULT FALSE,
    member_of_group TEXT,
    policy_item_code TEXT,

    source_url TEXT,
    scraped_at TIMESTAMP,
    translated_at TIMESTAMP,

    created_at TIMESTAMP NOT NULL DEFAULT now(),
    updated_at TIMESTAMP NOT NULL DEFAULT now()
);

CREATE INDEX idx_eu_additives_e_number ON aggregate.eu_additives(e_number);
CREATE INDEX idx_eu_additives_e_number_sort ON aggregate.eu_additives(e_number_sort);
CREATE INDEX idx_eu_additives_display_name_en ON aggregate.eu_additives(LOWER(display_name_en));
CREATE INDEX idx_eu_additives_display_name_lt ON aggregate.eu_additives(LOWER(display_name_lt));

CREATE TRIGGER trigger_update_eu_additives_updated_at
    BEFORE UPDATE ON aggregate.eu_additives
    FOR EACH ROW
    EXECUTE FUNCTION aggregate.update_updated_at_column();

CREATE TABLE aggregate.eu_additive_restrictions (
    id BIGSERIAL PRIMARY KEY,
    additive_id BIGINT NOT NULL REFERENCES aggregate.eu_additives(id) ON DELETE CASCADE,
    food_category_id TEXT,
    food_category_number TEXT,
    food_category_name_en TEXT,
    food_category_name_lt TEXT,
    restriction_type TEXT,
    restriction_value TEXT,
    restriction_unit TEXT,
    restriction_comment_en TEXT,
    restriction_comment_lt TEXT,
    note_number TEXT,
    note_text_en TEXT,
    note_text_lt TEXT,
    legislation_id BIGINT
);

CREATE INDEX idx_eu_additive_restrictions_additive_id ON aggregate.eu_additive_restrictions(additive_id);
CREATE INDEX idx_eu_additive_restrictions_category ON aggregate.eu_additive_restrictions(food_category_number);

CREATE TABLE aggregate.eu_additive_legislations (
    id BIGSERIAL PRIMARY KEY,
    additive_id BIGINT NOT NULL REFERENCES aggregate.eu_additives(id) ON DELETE CASCADE,
    eu_legislation_id BIGINT,
    title_en TEXT,
    title_lt TEXT,
    text TEXT,
    eurlex_link TEXT,
    publication_date DATE,
    date_entry_into_force DATE,
    oj_number TEXT,
    oj_page TEXT
);

CREATE INDEX idx_eu_additive_legislations_additive_id ON aggregate.eu_additive_legislations(additive_id);

