INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (318488, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (318488, 316916, 'Commission Regulation (EU) 380/2012 of 03/05/2012 amending Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for aluminium -containing food addtiives . TEXT with EEA relevance', 'Komisijos reglamentas (ES) 380/2012, 2012 m. gegužės 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl aliuminio turinčių maisto priedų naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 380/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:119:0014:0038:EN:PDF', NULL, NULL, 'L 119', '14');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (318488, 316926, 'Commission Regulation (EU) 438/2013 of 13/05/2013 amending and correcting Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 438/2013, 2013 m. gegužės 13 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 438/2013', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2013:129:0028:0033:EN:PDF', NULL, NULL, 'L129', '28');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (318488, 316316, 'Commission Regulation (EU) 509/2013 of 3/6/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of several additives in certain alcoholic beverages. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 509/2013, 2013 m. birželio 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl kelių priedų naudojimo tam tikruose alkoholiniuose gėrimuose. Tekstas svarbus EEE', '(EU) No 0509/2013', NULL, NULL, NULL, 'L 150', '13');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (318488, 316856, 'COMMISSION REGULATION (EU) 2018/1497 of 8 October 2018 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards food category 17 and the use of food additives in food supplements (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2018/1497 2018 m. spalio 8 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl 17 maisto kategorijos ir maisto priedų naudojimo maisto papilduose. (Tekstas svarbus EEE)', '(EU) No 2018/1497', NULL, NULL, NULL, 'L 253', '36');
