INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315574', '1.7.6', 'cheese products (excluding products falling in category 16)', 'sūrio produktai (išskyrus produktus, priklausančius 16 kategorijai)', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only flavoured unripened products', 'tik aromatizuoti nesubrandinti produktai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315610', '3', 'edible ices', 'valgomieji ledai', 'FAD_RT_ML', '150', 'FAD_RU_MGK', NULL, NULL, '25', 'The quantities of each of the colours E 122 and E 155 may not exceed 50 mg/kg or mg/l', 'Kiekvieno iš dažiklių E 122 ir E 155 kiekis neturi viršyti 50 mg/kg arba mg/l', 316226);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315654', '4.2.4.1', 'fruit and vegetable preparations excluding compote', 'vaisių ir daržovių preparatai, išskyrus kompotą', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only mostarda di frutta', 'tik mostarda di frutta', NULL, NULL, NULL, 316526);
