INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315950', '12.9', 'Protein products excluding products covered in category 1 8', 'Baltymų produktai, išskyrus produktus, priskiriamus 1 8 kategorijai', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only meat and fish analouges based on vegetable proteins', 'tik mėsos ir žuvies pakaitalai, pagaminti iš augalinių baltymų', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316050', '14.2.3', 'Cider and perry', 'Sidras ir kriaušių sidras', 'FAD_RT_ML', '200', 'FAD_RU_MGL', 'excluding cidre bouché, cydr jakościowy, perry jakościowe, cydr lodowy, perry lodowe', 'išskyrus cidre bouché, cydr jakościowy, perry jakościowe, cydr lodowy, perry lodowe', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316094', '15.2', 'Processed nuts', 'Perdirbtieji riešutai', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only savoury coated nuts', 'tik pikantiškai apvolioti riešutai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316110', '17.2', 'food supplements supplied in a liquid form excluding food supplements for Infants and young children', 'maisto papildai, tiekiami skystos formos, išskyrus maisto papildus kūdikiams ir mažiems vaikams', 'FAD_RT_ML', '100', 'FAD_RU_MGL', NULL, NULL, NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315526', '1.4', 'flavoured fermented milk products including heat-treated products', 'aromatizuoti fermentuoto pieno produktai, įskaitant termiškai apdorotus produktus', 'FAD_RT_ML', '150', 'FAD_RU_MGL', 'Period of application: from 1 August 2014', 'Taikymo laikotarpis: nuo 2014 m. rugpjūčio 1 d.', '74', 'Maximum limit for aluminium coming from all aluminium lakes 15 mg/kg. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Didžiausia aliuminio riba, gaunamo iš visų aliuminio lakelių, – 15 mg/kg. Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punkto tikslais ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316098', '16', 'Desserts excluding products covered in category 1 3 and 4', 'Desertai, išskyrus produktus, kuriems taikomos kategorijos 1, 3 ir 4', 'FAD_RT_ML', '150', 'FAD_RU_MGK', NULL, NULL, '74', 'Maximum limit for aluminium coming from all aluminium lakes 15 mg/kg. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Didžiausia aliuminio riba, gaunamo iš visų aliuminio lakelių, – 15 mg/kg. Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punkto tikslais ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315562', '1.7.3', 'edible cheese rind', 'valgoma sūrio plutelė', 'FAD_RT_QS', NULL, NULL, 'Period of application: from 1 August 2014', 'Taikymo laikotarpis: nuo 2014 m. rugpjūčio 1 d.', '67', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines and E 180 litholrubine BK 10 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų ir E 180 litolrubino BK aliuminio lakų, riba 10 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315810', '8.3.3', 'Casings and coatings and decorations for meat', 'Apvalkalai, dangalai ir mėsos dekoracijos', 'FAD_RT_ML', '500', 'FAD_RU_MGK', 'only decorations and coatings except edible external coating of pasturmas', 'tik dekoracijos ir dangos, išskyrus valgomąją išorinę pasturmas dangą', '78', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 10 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 10 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316090', '15.1', 'Potato- cereal- flour- or starch-based snacks', 'Bulvių, grūdų, miltų arba krakmolo pagrindu pagaminti užkandžiai', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only extruded or expanded savoury snack products', 'tik ekstruduoti arba išpūsti sūrūs užkandžiai', '71', 'Maximum limit for aluminium coming from all aluminium lakes 30 mg/kg. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Didžiausia aliuminio riba, gaunamo iš visų aliuminio lakelių, – 30 mg/kg. Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punkto tikslais ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315850', '9.3', 'fish roe', 'žuvų ikrai', 'FAD_RT_ML', '300', 'FAD_RU_MGK', 'except Sturgeons'' eggs (Caviar)', 'išskyrus eršketo ikrus (ikrai)', '86', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 3 mg/kg. As a derogation to this rule, the maximum limit only for pasteurised products shall be 50 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22(1)(g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 3 mg/kg. Nukrypstant nuo šios taisyklės, maksimali riba tik pasterizuotiems produktams yra 50 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316426);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316062', '14.2.6', 'Spirit drinks as defined in Regulation (EU) 2019/787', 'Spiritiniai gėrimai, kaip apibrėžta Reglamente (ES) 2019/787', 'FAD_RT_ML', '200', 'FAD_RU_MGL', 'except: spirit drinks as defined in categories 1-17, 22, 36, 37 and 41 of Annex I of Regulation (EU) 2019/787', 'išskyrus: stipriuosius alkoholinius gėrimus, kaip apibrėžta Reglamento (ES) 2019/787 I priedo 1–17, 22, 36, 37 ir 41 kategorijose', '87', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 1,5 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22(1)(g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 1,5 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316426);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316078', '14.2.7.3', 'Aromatised wine-product cocktails', 'Aromatizuotų vyno produktų kokteiliai', 'FAD_RT_ML', '200', 'FAD_RU_MGL', NULL, NULL, '87', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 1,5 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22(1)(g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 1,5 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316426);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316082', '14.2.8', 'Other alcoholic beverages including mixtures of alcoholic beverages with non-alcoholic beverages and other alcoholic beverages based on distilled alcohol with alcoholic strength by volume less than 15 %', 'Kiti alkoholiniai gėrimai, įskaitant alkoholinių gėrimų mišinius su nealkoholiniais gėrimais ir kitus distiliuotu alkoholiu pagrindu pagamintus alkoholinius gėrimus, kurių faktinė alkoholio koncentracija tūrio procentais yra mažesnė nei 15 %', 'FAD_RT_ML', '200', 'FAD_RU_MGL', 'only alcoholic beverages with alcoholic strength by volume less than 15 %', 'tik alkoholiniai gėrimai, kurių alkoholio kiekis tūrio procentais yra mažesnis nei 15 %', '87', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 1,5 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22(1)(g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 1,5 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316316);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315698', '5.3', 'chewing gum', 'kramtomoji guma', 'FAD_RT_ML', '300', 'FAD_RU_MGK', '', NULL, '25', 'The quantities of each of the colours E 122 and E 155 may not exceed 50 mg/kg or mg/l', 'Kiekvieno iš dažiklių E 122 ir E 155 kiekis neturi viršyti 50 mg/kg arba mg/l', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315702', '5.4', 'Decorations, coatings and fillings, except fruit-based fillings covered by category 4.2.4', 'Dekoracijos, dangos ir įdarai, išskyrus vaisių pagrindu pagamintus įdarus, kuriems taikoma kategorija 4.2.4', 'FAD_RT_ML', '300', 'FAD_RU_MGK', 'only fillings', 'tik įdarai', '25', 'The quantities of each of the colours E 122 and E 155 may not exceed 50 mg/kg or mg/l', 'Kiekvieno iš dažiklių E 122 ir E 155 kiekis neturi viršyti 50 mg/kg arba mg/l', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315922', '12.2.2', 'Seasonings and condiments', 'Prieskoniai ir pagardai', 'FAD_RT_ML', '500', 'FAD_RU_MGK', 'only seasonings, for example curry powder, tandoori', 'tik prieskoniai, pavyzdžiui, kario milteliai, tanduri', '70', 'Maximum limit for aluminium coming from all aluminium lakes 120 mg/kg. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Didžiausia aliuminio riba, gaunamo iš visų aliuminio lakelių, – 120 mg/kg. Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punkto tikslais ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316054', '14.2.4', 'Fruit wine and made wine', 'Vaisių vynas ir pagamintas vynas', 'FAD_RT_ML', '200', 'FAD_RU_MGL', 'excluding wino owocowe jakościowe', 'išskyrus wino owocowe jakościowe', NULL, NULL, NULL, 316316);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315782', '7.2', 'Fine bakery wares', 'Smulkūs kepiniai', 'FAD_RT_ML', '200', 'FAD_RU_MGK', NULL, NULL, '25', 'The quantities of each of the colours E 122 and E 155 may not exceed 50 mg/kg or mg/l', 'Kiekvieno iš dažiklių E 122 ir E 155 kiekis neturi viršyti 50 mg/kg arba mg/l', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315938', '12.6', 'Sauces', 'Padažai', 'FAD_RT_ML', '500', 'FAD_RU_MGK', 'including pickles, relishes, chutney and picalilli; excluding tomato-based sauces', 'įskaitant marinuotus agurkus, prieskonius, čatnius ir pikalilius; išskyrus pomidorų padažus', '65', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 10 mg/kg. No other aluminium lakes may be used. For the puroposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 10 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315694', '5.2', 'Other confectionery including breath freshening micro-sweets', 'Kiti konditerijos gaminiai, įskaitant kvapą gaivinančias mikrokarameliukus', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only candied fruit and vegetables', 'tik cukruoti vaisiai ir daržovės', '25', 'The quantities of each of the colours E 122 and E 155 may not exceed 50 mg/kg or mg/l', 'Kiekvieno iš dažiklių E 122 ir E 155 kiekis neturi viršyti 50 mg/kg arba mg/l', 316176);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '316106', '17.1', 'food supplements supplied in a solid form excluding food supplements for infants and young children’,', 'maisto papildai, tiekiami kietos formos, išskyrus maisto papildus kūdikiams ir mažiems vaikams', 'FAD_RT_ML', '300', 'FAD_RU_MGK', 'Period of application: until 31 July 2014', 'Taikymo laikotarpis: iki 2014 m. liepos 31 d.', '69', 'Maximum limit for aluminium coming from all aluminium lakes 150 mg/kg. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Didžiausia aliuminio riba, gaunamo iš visų aliuminio lakelių, – 150 mg/kg. Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punkto tikslais ši riba taikoma nuo 2013 m. vasario 1 d.', 316856);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '500', 'FAD_RU_MGK', 'only surimi and similar products and salmon substitutes based on Theragra chalcogramma, Pollachius virens and Clupea harengus’', 'tik surimi ir panašūs produktai bei lašišos pakaitalai, pagaminti iš Theragra chalcogramma, Pollachius virens ir Clupea harengus''', '84', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 4 mg/kg. As a derogation to this rule, the maximum limit only for salmon substitutes shall be 5,5 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22(1)(g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 4 mg/kg. Nukrypstant nuo šios taisyklės, maksimali riba tik lašišos pakaitalams yra 5,5 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316606);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '2694154', '18.2', 'Meal replacement for weight control as referred to in Commission Regulation (EU) No 432/2012', 'Maisto pakaitalai svoriui kontroliuoti, kaip nurodyta Komisijos reglamente (ES) Nr. 432/2012', 'FAD_RT_ML', '50', 'FAD_RU_MGK', NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2860631, '2747789', '14.1.4', 'Flavoured_drinks', 'Aromatizuoti gėrimai', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'excluding chocolate milk and malt products Period of application: until 31 July 2014', 'išskyrus šokoladinį pieną ir salyklo produktus. Taikymo laikotarpis: iki 2014 m. liepos 31 d.', NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316176, 'Regulation (EC) No 1333/2008 of the European Parliament and of the Council of 16/12/2008 on food additives. TEXT with EEA relevance', '2008 m. gruodžio 16 d. Europos Parlamento ir Tarybos reglamentas (EB) Nr. 1333/2008 dėl maisto priedų. Tekstas svarbus EEE', '(EC) No 1333/2008', NULL, NULL, NULL, 'L354', '16');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316226, 'Commission Regulation (EU) 232/2012 of 16/03/2012 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for Quinoline Yellow (E 104), Sunset Yellow FCF/Oragne Yellow (E110) and Ponceau 4R, Cochineal Red A (E124). TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 232/2012, 2012 m. kovo 16 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl chinolino geltonojo (E 104), saulėlydžio geltonojo FCF / apelsinų geltonojo (E110) ir Ponso 4R, košenilių raudonojo A (E124) naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 0232/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:078:0001:0012:EN:PDF', NULL, NULL, 'L 78', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316916, 'Commission Regulation (EU) 380/2012 of 03/05/2012 amending Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for aluminium -containing food addtiives . TEXT with EEA relevance', 'Komisijos reglamentas (ES) 380/2012, 2012 m. gegužės 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl aliuminio turinčių maisto priedų naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 380/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:119:0014:0038:EN:PDF', NULL, NULL, 'L 119', '14');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316316, 'Commission Regulation (EU) 509/2013 of 3/6/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of several additives in certain alcoholic beverages. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 509/2013, 2013 m. birželio 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl kelių priedų naudojimo tam tikruose alkoholiniuose gėrimuose. Tekstas svarbus EEE', '(EU) No 0509/2013', NULL, NULL, NULL, 'L 150', '13');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316426, 'Commission Regulation (EU) 923/2014 of 25/08/2014 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of aluminium lakes of riboflavins (E101) and cochineal, carminic acid, carmines (E120) in certain food categories and Annex to Regulation (EU) 231/2012 as regards the specifications for riboflavins (E101) . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 923/2014, 2014 m. rugpjūčio 25 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl riboflavinų (E101) ir košenilės, karminų rūgšties, karminų (E120) aliuminio lakelių naudojimo tam tikrose maisto kategorijose ir Reglamento (ES) 231/2012 priedas dėl riboflavinų (E101) specifikacijų. Tekstas svarbus EEE', '(EU) No 0923/2014', NULL, NULL, NULL, 'L 252', '11');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316616, 'Commission Regulation (EU) 2015/537 of 31/3/2015 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of aluminium lakes of cochineal, carminic acid, carmines (E120) in dietary foods for special medical purposes. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/537, 2015 m. kovo 31 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl košenilės, karminų rūgšties, karminų (E120) aliuminio lakelių naudojimo specialios medicininės paskirties dietiniuose maisto produktuose. Tekstas svarbus EEE', '(EU) No 2015/0537', NULL, NULL, NULL, 'L 88', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316856, 'COMMISSION REGULATION (EU) 2018/1497 of 8 October 2018 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards food category 17 and the use of food additives in food supplements (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2018/1497 2018 m. spalio 8 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl 17 maisto kategorijos ir maisto priedų naudojimo maisto papilduose. (Tekstas svarbus EEE)', '(EU) No 2018/1497', NULL, NULL, NULL, 'L 253', '36');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 316606, 'COMMISSION REGULATION (EU) 2020/1819 of 2 December 2020 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of colours in salmon substitutes (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2020/1819 2020 m. gruodžio 2 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl dažiklių naudojimo lašišos pakaitaluose. (Tekstas svarbus EEE)', '(EU) No 1819/2020', NULL, NULL, NULL, 'L406', '26');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (2860631, 1764184, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
