INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315570', '1.7.5', 'processed cheese', 'perdirbtas sūris', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only flavoured processed cheese', 'tik aromatizuotas perdirbtas sūris', '33', 'Maximum individually or for the combination of E 100, E 102, E 120, E 122, E 160e and E 161b', 'Didžiausia riba atskirai arba E 100, E 102, E 120, E 122, E 160e ir E 161b deriniui', 316226);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315590', '2.1', 'fats and oils essentially free from water (excluding anhydrous milk fat)', 'riebalai ir aliejai, iš esmės neturintys vandens (išskyrus bevandenį pieno riebalą)', 'FAD_RT_QS', NULL, NULL, 'only fats', 'tik riebalai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '2696141', '2.2.2', 'Other fat and oil emulsions including spreads as defined by Regulation (EC) No 1234/2007 and liquid emulsions', 'Kitos riebalų ir aliejų emulsijos, įskaitant tepius produktus, kaip apibrėžta Reglamente (EB) Nr. 1234/2007, ir skystąsias emulsijas', 'FAD_RT_QS', NULL, NULL, 'excluding reduced fat butter', 'išskyrus sumažinto riebumo sviestą', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315662', '4.2.5', 'jam jellies and marmalades and similar products', 'uogienės, želė, marmeladai ir panašūs produktai', 'FAD_RT_QS', NULL, NULL, 'except chestnut puree', 'išskyrus kaštonų tyrę', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315674', '4.2.5.3', 'other similar fruit or vegetable spreads', 'kiti panašūs vaisių arba daržovių tepiniai', 'FAD_RT_QS', NULL, NULL, 'except crème de pruneaux', 'išskyrus crème de pruneaux', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315682', '4.2.6', 'processed potato products', 'perdirbti bulvių produktai', 'FAD_RT_QS', NULL, NULL, 'only dried potato granules and flakes', 'tik džiovintų bulvių granulės ir dribsniai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315802', '8.3.1', 'Non-heat-treated processed meat', 'Termiškai neapdoroti perdirbti mėsos produktai', 'FAD_RT_ML', '20', 'FAD_RU_MGK', 'only sausages', 'tik dešrelės', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315806', '8.3.2', 'Heat-treated processed meat', 'Termiškai apdorota perdirbta mėsa', 'FAD_RT_ML', '20', 'FAD_RU_MGK', 'only sausages, patés and terrines', 'tik dešrelės, paštetai ir terinai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315810', '8.3.3', 'Casings and coatings and decorations for meat', 'Apvalkalai, dangalai ir mėsos dekoracijos', 'FAD_RT_QS', NULL, NULL, 'only edible external coating of pasturmas', 'tik valgomasis išorinis pasturmos apvalkalas', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '100', NULL, 'only fish paste and crustacean paste', 'tik žuvies pasta ir vėžiagyvių pasta', '35', 'Maximum individually or for the combination of E 100, E 102, E 120, E 122, E 142, E 151, E 160e, E 161b', 'Didžiausia riba atskirai arba E 100, E 102, E 120, E 122, E 142, E 151, E 160e, E 161b deriniui', 316926);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (320157, '316070', '14.2.7.1', 'Aromatised wines', 'Aromatizuoti vynai', 'FAD_RT_ML', '100', 'FAD_RU_MGL', 'only americano, bitter vino', 'tik americano, bitter vino', '26', 'In americano E 100, E 101, E 102, E 104, E 120, E 122, E 123, E 124 are authorised individually or in combination', 'Americano sudėtyje E 100, E 101, E 102, E 104, E 120, E 122, E 123, E 124 leidžiami atskirai arba kartu', 316526);
