INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320157, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320157, 316226, 'Commission Regulation (EU) 232/2012 of 16/03/2012 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for Quinoline Yellow (E 104), Sunset Yellow FCF/Oragne Yellow (E110) and Ponceau 4R, Cochineal Red A (E124). TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 232/2012, 2012 m. kovo 16 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl chinolino geltonojo (E 104), saulėlydžio geltonojo FCF / apelsinų geltonojo (E110) ir Ponso 4R, košenilių raudonojo A (E124) naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 0232/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:078:0001:0012:EN:PDF', NULL, NULL, 'L 78', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320157, 316926, 'Commission Regulation (EU) 438/2013 of 13/05/2013 amending and correcting Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 438/2013, 2013 m. gegužės 13 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 438/2013', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2013:129:0028:0033:EN:PDF', NULL, NULL, 'L129', '28');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320157, 316386, 'Commission Regulation (EU) 738/2013 of 30/07/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain additives in seaweed based fish roe analogues. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 738/2013, 2013 m. liepos 30 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų priedų naudojimo dumblių pagrindu pagamintuose žuvies ikrų analoguose. Tekstas svarbus EEE', '(EU) No 0738/2013', NULL, NULL, NULL, 'L 204', '32');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320157, 316356, 'Commission Regulation (EU) 601/2014 of 4/6/2014 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the food categories of meat and the use of certain food additives in meat preparations. TEXT with EEA relevance', 'Komisijos reglamentas (ES) 601/2014, 2014 m. birželio 4 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl mėsos maisto kategorijų ir tam tikrų maisto priedų naudojimo mėsos pusgaminiuose. Tekstas svarbus EEE', '(EU) No 0601/2014', NULL, NULL, NULL, 'L 166', '11');
