INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320772, 316916, 'Commission Regulation (EU) 380/2012 of 03/05/2012 amending Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for aluminium -containing food addtiives . TEXT with EEA relevance', 'Komisijos reglamentas (ES) 380/2012, 2012 m. gegužės 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl aliuminio turinčių maisto priedų naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 380/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:119:0014:0038:EN:PDF', NULL, NULL, 'L 119', '14');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320772, 316926, 'Commission Regulation (EU) 438/2013 of 13/05/2013 amending and correcting Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 438/2013, 2013 m. gegužės 13 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 438/2013', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2013:129:0028:0033:EN:PDF', NULL, NULL, 'L129', '28');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320772, 316636, 'Commission Regulation (EU) 2015/647 of 24/04/2015 amending and correcting Annexes II and III to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/647, 2015 m. balandžio 24 d., kuriuo iš dalies keičiami ir taisomi Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II ir III priedai dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 2015/0647', NULL, NULL, NULL, '107', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (320772, 316856, 'COMMISSION REGULATION (EU) 2018/1497 of 8 October 2018 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards food category 17 and the use of food additives in food supplements (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2018/1497 2018 m. spalio 8 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl 17 maisto kategorijos ir maisto priedų naudojimo maisto papilduose. (Tekstas svarbus EEE)', '(EU) No 2018/1497', NULL, NULL, NULL, 'L 253', '36');
