INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321290, '316110', '17.2', 'food supplements supplied in a liquid form excluding food supplements for Infants and young children', 'maisto papildai, tiekiami skystos formos, išskyrus maisto papildus kūdikiams ir mažiems vaikams', 'FAD_RT_ML', '10', 'FAD_RU_MGL', 'Period of application: from 1 August 2014', 'Taikymo laikotarpis: nuo 2014 m. rugpjūčio 1 d.', '61', 'The total quantity of E 104, E 110, E 124 and the colours in Group III shall not exceed the maximum listed for Group III', 'Bendras E 104, E 110, E 124 ir III grupės dažiklių kiekis neturi viršyti III grupei nustatyto didžiausio kiekio', 316856);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321290, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only salmon substitutes based on Theragra chalcogramma, Pollachius virens and Clupea harengus', 'tik lašišos pakaitalai pagaminti iš Theragra chalcogramma, Pollachius virens ir Clupea harengus', '63', 'The total quantity of E 110, E 124 and the colours in Group III shall not exceed the maximum listed for Group III', 'Bendras E 110, E 124 ir III grupės dažiklių kiekis neturi viršyti III grupei nustatyto didžiausio kiekio', 316606);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321290, '2694154', '18.2', 'Meal replacement for weight control as referred to in Commission Regulation (EU) No 432/2012', 'Maisto pakaitalai svoriui kontroliuoti, kaip nurodyta Komisijos reglamente (ES) Nr. 432/2012', NULL, '10', 'FAD_RU_MGK', NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321290, '2747789', '14.1.4', 'Flavoured_drinks', 'Aromatizuoti gėrimai', 'FAD_RT_ML', '20', 'FAD_RU_MGL', 'excluding chocolate milk and malt products', 'išskyrus šokoladinį pieną ir salyklo produktus', NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321290, 316226, 'Commission Regulation (EU) 232/2012 of 16/03/2012 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for Quinoline Yellow (E 104), Sunset Yellow FCF/Oragne Yellow (E110) and Ponceau 4R, Cochineal Red A (E124). TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 232/2012, 2012 m. kovo 16 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl chinolino geltonojo (E 104), saulėlydžio geltonojo FCF / apelsinų geltonojo (E110) ir Ponso 4R, košenilių raudonojo A (E124) naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 0232/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:078:0001:0012:EN:PDF', NULL, NULL, 'L 78', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321290, 316916, 'Commission Regulation (EU) 380/2012 of 03/05/2012 amending Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for aluminium -containing food addtiives . TEXT with EEA relevance', 'Komisijos reglamentas (ES) 380/2012, 2012 m. gegužės 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl aliuminio turinčių maisto priedų naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 380/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:119:0014:0038:EN:PDF', NULL, NULL, 'L 119', '14');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321290, 316926, 'Commission Regulation (EU) 438/2013 of 13/05/2013 amending and correcting Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 438/2013, 2013 m. gegužės 13 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 438/2013', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2013:129:0028:0033:EN:PDF', NULL, NULL, 'L129', '28');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321290, 316636, 'Commission Regulation (EU) 2015/647 of 24/04/2015 amending and correcting Annexes II and III to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/647, 2015 m. balandžio 24 d., kuriuo iš dalies keičiami ir taisomi Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II ir III priedai dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 2015/0647', NULL, NULL, NULL, '107', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321290, 316856, 'COMMISSION REGULATION (EU) 2018/1497 of 8 October 2018 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards food category 17 and the use of food additives in food supplements (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2018/1497 2018 m. spalio 8 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl 17 maisto kategorijos ir maisto priedų naudojimo maisto papilduose. (Tekstas svarbus EEE)', '(EU) No 2018/1497', NULL, NULL, NULL, 'L 253', '36');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321290, 316606, 'COMMISSION REGULATION (EU) 2020/1819 of 2 December 2020 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of colours in salmon substitutes (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2020/1819 2020 m. gruodžio 2 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl dažiklių naudojimo lašišos pakaitaluose. (Tekstas svarbus EEE)', '(EU) No 1819/2020', NULL, NULL, NULL, 'L406', '26');
