INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315638', '4.2.1', 'dried fruit and vegetables', 'džiovinti vaisiai ir daržovės', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only preserves of red fruit', 'tik konservuoti raudonieji vaisiai', '34', 'Maximum individually or for the combination of E 120, E 122, E 129, E 131 and E 133', 'Didžiausia riba atskirai arba E 120, E 122, E 129, E 131 ir E 133 deriniui', 316226);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315642', '4.2.2', 'fruit and vegetables in vinegar oil or brine', 'vaisiai ir daržovės acte, aliejuje arba sūryme', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only preserves of red fruit', 'tik konservuoti raudonieji vaisiai', '34', 'Maximum individually or for the combination of E 120, E 122, E 129, E 131 and E 133', 'Didžiausia riba atskirai arba E 120, E 122, E 129, E 131 ir E 133 deriniui', 316226);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315646', '4.2.3', 'canned or bottled fruit and vegetables', 'konservuoti arba buteliuose supilti vaisiai ir daržovės', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only preserves of red fruit', 'tik konservuoti raudonieji vaisiai', '34', 'Maximum individually or for the combination of E 120, E 122, E 129, E 131 and E 133', 'Didžiausia riba atskirai arba E 120, E 122, E 129, E 131 ir E 133 deriniui', 316226);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315674', '4.2.5.3', 'other similar fruit or vegetable spreads', 'kiti panašūs vaisių arba daržovių tepiniai', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'except crème de pruneaux', 'išskyrus crème de pruneaux', '31', 'Maximum individually or in combination with E 120, E 142, E 160d and E 161b', 'Didžiausia riba atskirai arba derinyje su E 120, E 142, E 160d ir E 161b', 316226);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315726', '6.3', 'breakfast cereals', 'pusryčių dribsniai', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only fruit flavoured breakfast cereals', 'tik vaisių skonio pusryčių dribsniai', '53', 'E 120, E 162 and E 163 may be added individually or in combination', 'E 120, E 162 ir E 163 gali būti dedami atskirai arba kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315558', '1.7.2', 'ripened cheese', 'subrandintas sūris', 'FAD_RT_ML', '125', 'FAD_RU_MGK', 'only red marbled cheese and red pesto cheese', 'tik raudonasis marmurinis sūris ir raudonasis pesto sūris', '83', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 3,2 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22(1)(g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 3,2 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316516);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '316070', '14.2.7.1', 'Aromatised wines', 'Aromatizuoti vynai', 'FAD_RT_ML', '100', 'FAD_RU_MGL', 'only americano, bitter vino', 'tik americano, bitter vino', '26', 'In americano E 100, E 101, E 102, E 104, E 120, E 122, E 123, E 124 are authorised individually or in combination', 'Americano sudėtyje E 100, E 101, E 102, E 104, E 120, E 122, E 123, E 124 leidžiami atskirai arba kartu', 316426);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '316074', '14.2.7.2', 'Aromatised wine-based drinks', 'Aromatizuoti vyno pagrindu gaminami gėrimai', 'FAD_RT_ML', '100', 'FAD_RU_MGL', 'only bitter soda', 'tik bitter soda', '28', 'In bitter soda E 100, E 101, E 102, E 104, E 110, E 120, E 122, E 123, E 124, E 129 are authorised individually or in combination', 'Karčiojoje sodoje E 100, E 101, E 102, E 104, E 110, E 120, E 122, E 123, E 124, E 129 leidžiami atskirai arba kartu', 316426);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only breakfast sausages with a minimum cereal content of 6 %, burger meat with a minimum vegetable and/or cereal content of 4 % mixed within the meat (in these products, the meat is minced in such a way so that the muscle and fat tissue are completely dispersed, so that fibre makes an emulsion with the fat, giving those products their typical appearance), merguez type products, salsicha fresca, mici, butifarra fresca, longaniza fresca, chorizo fresco, cevapcici and pljeskav', 'tik pusryčių dešrelės, kurių minimalus grūdų kiekis yra 6 %, faršo kotletai, kurių minimalus daržovių ir (arba) grūdų kiekis, sumaišytas su mėsa, yra 4 % (šiuose produktuose mėsa smulkinama taip, kad raumenų ir riebalų audiniai būtų visiškai išsklaidyti, todėl skaidulinės medžiagos sudaro emulsiją su riebalais, suteikdamos šiems produktams būdingą išvaizdą), merguez tipo produktai, salsicha fresca, mici, butifarra fresca, longaniza fresca, chorizo fresco, cevapcici ir pljeskav', '66', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 1,5 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 1,5 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316356);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315570', '1.7.5', 'processed cheese', 'perdirbtas sūris', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only flavoured processed cheese Period of application: until 31 July 2014', 'tik aromatizuotas perdirbtas sūris. Taikymo laikotarpis: iki 2014 m. liepos 31 d.', '33', 'Maximum individually or for the combination of E 100, E 102, E 120, E 122, E 160e and E 161b', 'Didžiausia riba atskirai arba E 100, E 102, E 120, E 122, E 160e ir E 161b deriniui', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315806', '8.3.2', 'Heat-treated processed meat', 'Termiškai apdorota perdirbta mėsa', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only sausages, pat&eacute;s and terrines', 'tik dešrelės, paštetai ir terinai', '66', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 1,5 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 1,5 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315810', '8.3.3', 'Casings and coatings and decorations for meat', 'Apvalkalai, dangalai ir mėsos dekoracijos', 'FAD_RT_QS', NULL, NULL, 'only edible external coating of pasturmas', 'tik valgomasis išorinis pasturmos apvalkalas', '78', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 10 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 10 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315654', '4.2.4.1', 'fruit and vegetable preparations excluding compote', 'vaisių ir daržovių preparatai, išskyrus kompotą', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'Only seaweed based fish roe analogues', 'Tik iš jūros dumblių pagaminti žuvų ikrų pakaitalai', '34', 'Maximum individually or for the combination of E 120, E 122, E 129, E 131 and E 133', 'Didžiausia riba atskirai arba E 120, E 122, E 129, E 131 ir E 133 deriniui', 316386);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315662', '4.2.5', 'jam jellies and marmalades and similar products', 'uogienės, želė, marmeladai ir panašūs produktai', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'except chestnut puree', 'išskyrus kaštonų tyrę', '31', 'Maximum individually or in combination with E 120, E 142, E 160d and E 161b', 'Didžiausia riba atskirai arba derinyje su E 120, E 142, E 160d ir E 161b', 316386);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only fish paste and crustacean paste', 'tik žuvies pasta ir vėžiagyvių pasta', '35', 'Maximum individually or for the combination of E 100, E 102, E 120, E 122, E 142, E 151, E 160e, E 161b', 'Didžiausia riba atskirai arba E 100, E 102, E 120, E 122, E 142, E 151, E 160e, E 161b deriniui', 316426);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315990', '13.1.4', NULL, NULL, 'FAD_RT_ML', '50', 'FAD_RU_MGK', 'Group III Colours with combined maximum limit (Part E of Annexx II to Regulation No 1333/2008)', 'III grupė, dažikliai su bendru didžiausiu leistinu kiekiu (Reglamento Nr. 1333/2008 II priedo E dalis)', '88', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 3 mg/kg only in liquid heat-treated products. No other aluminium lakes may be used. For the purposes of Article 22(1)(g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 3 mg/kg tik skystuose termiškai apdorotuose produktuose. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316616);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (321786, '315802', '8.3.1', 'Non-heat-treated processed meat', 'Termiškai neapdoroti perdirbti mėsos produktai', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only sausages', 'tik dešrelės', '66', 'Maximum limit for aluminium coming from aluminium lakes of E 120 cochineal, carminic acid, carmines 1,5 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 120 košenilio, karmiino rūgšties, karminų aliuminio lakų, riba 1,5 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316866);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316226, 'Commission Regulation (EU) 232/2012 of 16/03/2012 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for Quinoline Yellow (E 104), Sunset Yellow FCF/Oragne Yellow (E110) and Ponceau 4R, Cochineal Red A (E124). TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 232/2012, 2012 m. kovo 16 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl chinolino geltonojo (E 104), saulėlydžio geltonojo FCF / apelsinų geltonojo (E110) ir Ponso 4R, košenilių raudonojo A (E124) naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 0232/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:078:0001:0012:EN:PDF', NULL, NULL, 'L 78', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316916, 'Commission Regulation (EU) 380/2012 of 03/05/2012 amending Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for aluminium -containing food addtiives . TEXT with EEA relevance', 'Komisijos reglamentas (ES) 380/2012, 2012 m. gegužės 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl aliuminio turinčių maisto priedų naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 380/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:119:0014:0038:EN:PDF', NULL, NULL, 'L 119', '14');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316386, 'Commission Regulation (EU) 738/2013 of 30/07/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain additives in seaweed based fish roe analogues. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 738/2013, 2013 m. liepos 30 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų priedų naudojimo dumblių pagrindu pagamintuose žuvies ikrų analoguose. Tekstas svarbus EEE', '(EU) No 0738/2013', NULL, NULL, NULL, 'L 204', '32');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316356, 'Commission Regulation (EU) 601/2014 of 4/6/2014 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the food categories of meat and the use of certain food additives in meat preparations. TEXT with EEA relevance', 'Komisijos reglamentas (ES) 601/2014, 2014 m. birželio 4 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl mėsos maisto kategorijų ir tam tikrų maisto priedų naudojimo mėsos pusgaminiuose. Tekstas svarbus EEE', '(EU) No 0601/2014', NULL, NULL, NULL, 'L 166', '11');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316516, 'Commission Regulation (EU) No 1093/2014 of 16/10/2014 amending and correcting Annex II of Regulation (EC) 1333/2008 of European Parliament and of the Council as regards the use of certain colours in flavoured ripened cheese. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1093/2014 2014 m. spalio 16 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų dažiklių naudojimo aromatizuotame brandintame sūryje. Tekstas svarbus EEE.', '(EU) No 1093/2014', NULL, NULL, NULL, 'L 299', '22');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316426, 'Commission Regulation (EU) 923/2014 of 25/08/2014 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of aluminium lakes of riboflavins (E101) and cochineal, carminic acid, carmines (E120) in certain food categories and Annex to Regulation (EU) 231/2012 as regards the specifications for riboflavins (E101) . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 923/2014, 2014 m. rugpjūčio 25 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl riboflavinų (E101) ir košenilės, karminų rūgšties, karminų (E120) aliuminio lakelių naudojimo tam tikrose maisto kategorijose ir Reglamento (ES) 231/2012 priedas dėl riboflavinų (E101) specifikacijų. Tekstas svarbus EEE', '(EU) No 0923/2014', NULL, NULL, NULL, 'L 252', '11');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316616, 'Commission Regulation (EU) 2015/537 of 31/3/2015 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of aluminium lakes of cochineal, carminic acid, carmines (E120) in dietary foods for special medical purposes. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/537, 2015 m. kovo 31 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl košenilės, karminų rūgšties, karminų (E120) aliuminio lakelių naudojimo specialios medicininės paskirties dietiniuose maisto produktuose. Tekstas svarbus EEE', '(EU) No 2015/0537', NULL, NULL, NULL, 'L 88', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 316866, 'COMMISSION REGULATION (EU) 2019/800 of 17 May 2019 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the extension of the use of carminic acid, carmine (E 120) in certain meat products traditional in French Overseas Territories (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2019/800 2019 m. gegužės 17 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl karminų rūgšties, karmino (E 120) naudojimo srities išplėtimo tam tikruose mėsos produktuose, tradiciniuose Prancūzijos užjūrio teritorijose. (Tekstas svarbus EEE)', '(EU) No 2019/0800', NULL, NULL, NULL, '132', '15');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (321786, 2690778, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
