INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (322348, '316062', '14.2.6', 'Spirit drinks as defined in Regulation (EU) 2019/787', 'Spiritiniai gėrimai, kaip apibrėžta Reglamente (ES) 2019/787', 'FAD_RT_ML', '30', 'FAD_RU_MGL', 'except: spirit drinks as defined in categories 1-17, 22, 36, 37 and 41 of Annex I of Regulation (EU) 2019/787', 'išskyrus: stipriuosius alkoholinius gėrimus, kaip apibrėžta Reglamento (ES) 2019/787 I priedo 1–17, 22, 36, 37 ir 41 kategorijose', NULL, NULL, NULL, 316926);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (322348, '316070', '14.2.7.1', 'Aromatised wines', 'Aromatizuoti vynai', 'FAD_RT_ML', '30', 'FAD_RU_MGL', 'only wine-based aperitif’', 'tik vynu pagrįsti aperityvai', '26', 'In americano E 100, E 101, E 102, E 104, E 120, E 122, E 123, E 124 are authorised individually or in combination', 'Americano sudėtyje E 100, E 101, E 102, E 104, E 120, E 122, E 123, E 124 leidžiami atskirai arba kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (322348, '316066', '14.2.7', 'Aromatised wine products as defined by Regulation (EU) No 251/2014', 'Aromatizuoti vyno produktai, kaip apibrėžta Reglamente (ES) Nr. 251/2014', 'FAD_RT_ML', '100', 'FAD_RU_MGL', 'only bitter soda', 'tik bitter soda', '28', 'In bitter soda E 100, E 101, E 102, E 104, E 110, E 120, E 122, E 123, E 124, E 129 are authorised individually or in combination', 'Karčiojoje sodoje E 100, E 101, E 102, E 104, E 110, E 120, E 122, E 123, E 124, E 129 leidžiami atskirai arba kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (322348, '315850', '9.3', 'fish roe', 'žuvų ikrai', 'FAD_RT_ML', '30', 'FAD_RU_MGK', 'except Sturgeons'' eggs (Caviar)', 'išskyrus eršketo ikrus (ikrai)', '68', 'Maximum limit for aluminium coming from aluminium lakes of E 123 amaranth 10 mg/kg. No other aluminium lakes may be used. For the purposes of Article 22 (1) (g) of Regulation (EC) No 1333/2008 that limit shall apply from 1 February 2013', 'Maksimali aliuminio, gaunamo iš E 123 amaranto aliuminio lakų, riba 10 mg/kg. Jokie kiti aliuminio lakai negali būti naudojami. Taikant Reglamento (EB) Nr. 1333/2008 22 straipsnio 1 dalies g punktą, ši riba taikoma nuo 2013 m. vasario 1 d.', 316916);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (322348, '316082', '14.2.8', 'Other alcoholic beverages including mixtures of alcoholic beverages with non-alcoholic beverages and other alcoholic beverages based on distilled alcohol with alcoholic strength by volume less than 15 %', 'Kiti alkoholiniai gėrimai, įskaitant alkoholinių gėrimų mišinius su nealkoholiniais gėrimais ir kitus distiliuotu alkoholiu pagrindu pagamintus alkoholinius gėrimus, kurių faktinė alkoholio koncentracija tūrio procentais yra mažesnė nei 15 %', 'FAD_RT_ML', '30', 'FAD_RU_MGL', 'only alcoholic beverages with alcoholic strength by volume less than 15 %', 'tik alkoholiniai gėrimai, kurių alkoholio kiekis tūrio procentais yra mažesnis nei 15 %', NULL, NULL, NULL, 316316);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (322348, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (322348, 316916, 'Commission Regulation (EU) 380/2012 of 03/05/2012 amending Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for aluminium -containing food addtiives . TEXT with EEA relevance', 'Komisijos reglamentas (ES) 380/2012, 2012 m. gegužės 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl aliuminio turinčių maisto priedų naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 380/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:119:0014:0038:EN:PDF', NULL, NULL, 'L 119', '14');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (322348, 316926, 'Commission Regulation (EU) 438/2013 of 13/05/2013 amending and correcting Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 438/2013, 2013 m. gegužės 13 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 438/2013', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2013:129:0028:0033:EN:PDF', NULL, NULL, 'L129', '28');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (322348, 316316, 'Commission Regulation (EU) 509/2013 of 3/6/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of several additives in certain alcoholic beverages. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 509/2013, 2013 m. birželio 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl kelių priedų naudojimo tam tikruose alkoholiniuose gėrimuose. Tekstas svarbus EEE', '(EU) No 0509/2013', NULL, NULL, NULL, 'L 150', '13');
