INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (322483, '316110', '17.2', 'food supplements supplied in a liquid form excluding food supplements for Infants and young children', 'maisto papildai, tiekiami skystos formos, išskyrus maisto papildus kūdikiams ir mažiems vaikams', 'FAD_RT_ML', '10', 'FAD_RU_MGL', 'Period of application: from 1 January 2014 to 31 July 2014', 'Taikymo laikotarpis: nuo 2014 m. sausio 1 d. iki 2014 m. liepos 31 d.', '61', 'The total quantity of E 104, E 110, E 124 and the colours in Group III shall not exceed the maximum listed for Group III', 'Bendras E 104, E 110, E 124 ir III grupės dažiklių kiekis neturi viršyti III grupei nustatyto didžiausio kiekio', 316856);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (322483, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only salmon substitutes based on Theragra chalcogramma, Pollachius virens and Clupea harengus', 'tik lašišos pakaitalai pagaminti iš Theragra chalcogramma, Pollachius virens ir Clupea harengus', '63', 'The total quantity of E 110, E 124 and the colours in Group III shall not exceed the maximum listed for Group III', 'Bendras E 110, E 124 ir III grupės dažiklių kiekis neturi viršyti III grupei nustatyto didžiausio kiekio', 316606);
