INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (323019, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_ML', '25', 'FAD_RU_MGK', 'only breakfast sausages with a minimum cereal content of 6 % and burger meat with a minimum vegetable and/or cereal content of 4 % mixed within the meat; In these products, the meat is minced in such a way so that the muscle and fat tissue are completely dispersed, so that fibre makes an emulsion with the fat, giving those products their typical appearance', 'tik pusryčių dešrelės, kurių minimalus grūdų kiekis yra 6 %, ir faršo kotletai, kurių minimalus daržovių ir (arba) grūdų kiekis, sumaišytas su mėsa, yra 4 %; šiuose produktuose mėsa smulkinama taip, kad raumenų ir riebalų audiniai būtų visiškai išsklaidyti, todėl skaidulinės medžiagos sudaro emulsiją su riebalais, suteikdamos šiems produktams būdingą išvaizdą', NULL, NULL, NULL, 316526);
