INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (323891, '316050', '14.2.3', 'Cider and perry', 'Sidras ir kriaušių sidras', 'FAD_RT_QS', NULL, NULL, 'only cidre bouché', 'tik cidre bouché', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (323891, '316062', '14.2.6', 'Spirit drinks as defined in Regulation (EU) 2019/787', 'Spiritiniai gėrimai, kaip apibrėžta Reglamente (ES) 2019/787', 'FAD_RT_QS', NULL, NULL, 'except: spirit drinks as defined in categories 15-17, 22, 36, 37 and 41 of Annex I of Regulation (EU) 2019/787 category 2 of Annex I of Regulation (EU) 2019/787 can only contain E 150a category 1, 3-8, 10-14 of Annex I of Regulation (EU) 2019/787 can only contain added caramel as a means of adjusting the colour', 'išskyrus: stipriuosius alkoholinius gėrimus, kaip apibrėžta Reglamento (ES) 2019/787 I priedo 15–17, 22, 36, 37 ir 41 kategorijose; Reglamento (ES) 2019/787 I priedo 2 kategorija gali būti naudojamas tik E 150a; Reglamento (ES) 2019/787 I priedo 1, 3–8, 10–14 kategorijos gali būti naudojamas tik pridėtas karamelinis cukrus spalvai koreguoti', NULL, NULL, NULL, 316926);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (323891, '316070', '14.2.7.1', 'Aromatised wines', 'Aromatizuoti vynai', 'FAD_RT_QS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 316926);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (323891, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_QS', NULL, NULL, 'only breakfast sausages with a minimum cereal content of 6 %, burger meat with a minimum vegetable and/or cereal content of 4 % mixed within the meat (in these products, the meat is minced in such a way so that the muscle and fat tissue are completely dispersed, so that fibre makes an emulsion with the fat, giving those products their typical appearance), merguez type products, salsicha fresca, mici, butifarra fresca, longaniza fresca and chorizo fresco', 'tik pusryčių dešrelės, kurių minimalus grūdų kiekis yra 6 %, faršo kotletai, kurių minimalus daržovių ir (arba) grūdų kiekis, sumaišytas su mėsa, yra 4 % (šiuose produktuose mėsa smulkinama taip, kad raumenų ir riebalų audiniai būtų visiškai išsklaidyti, todėl skaidulinės medžiagos sudaro emulsiją su riebalais, suteikdamos šiems produktams būdingą išvaizdą), merguez tipo produktai, salsicha fresca, mici, butifarra fresca, longaniza fresca ir chorizo fresco', NULL, NULL, NULL, 316356);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (323891, '316074', '14.2.7.2', 'Aromatised wine-based drinks', 'Aromatizuoti vyno pagrindu gaminami gėrimai', 'FAD_RT_QS', NULL, NULL, 'except sangria, clarea, zurra', 'išskyrus sangria, clarea, zurra', NULL, NULL, NULL, 316636);
