INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (325160, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (325160, 316226, 'Commission Regulation (EU) 232/2012 of 16/03/2012 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the conditions of use and the use levels for Quinoline Yellow (E 104), Sunset Yellow FCF/Oragne Yellow (E110) and Ponceau 4R, Cochineal Red A (E124). TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 232/2012, 2012 m. kovo 16 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl chinolino geltonojo (E 104), saulėlydžio geltonojo FCF / apelsinų geltonojo (E110) ir Ponso 4R, košenilių raudonojo A (E124) naudojimo sąlygų ir lygių. Tekstas svarbus EEE', '(EU) No 0232/2012', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2012:078:0001:0012:EN:PDF', NULL, NULL, 'L 78', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (325160, 316316, 'Commission Regulation (EU) 509/2013 of 3/6/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of several additives in certain alcoholic beverages. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 509/2013, 2013 m. birželio 3 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl kelių priedų naudojimo tam tikruose alkoholiniuose gėrimuose. Tekstas svarbus EEE', '(EU) No 0509/2013', NULL, NULL, NULL, 'L 150', '13');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (325160, 316606, 'COMMISSION REGULATION (EU) 2020/1819 of 2 December 2020 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of colours in salmon substitutes (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2020/1819 2020 m. gruodžio 2 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl dažiklių naudojimo lašišos pakaitaluose. (Tekstas svarbus EEE)', '(EU) No 1819/2020', NULL, NULL, NULL, 'L406', '26');
