INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (324915, '315558', '1.7.2', 'ripened cheese', 'subrandintas sūris', 'FAD_RT_QS', NULL, NULL, 'only ripened orange, yellow and broken-white cheese and red pesto cheese', 'tik prinokę oranžiniai, geltoni ir sulaužytos baltos spalvos sūriai bei raudonų pesto sūriai', NULL, NULL, NULL, 316516);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (324915, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (324915, 316386, 'Commission Regulation (EU) 738/2013 of 30/07/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain additives in seaweed based fish roe analogues. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 738/2013, 2013 m. liepos 30 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų priedų naudojimo dumblių pagrindu pagamintuose žuvies ikrų analoguose. Tekstas svarbus EEE', '(EU) No 0738/2013', NULL, NULL, NULL, 'L 204', '32');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (324915, 316356, 'Commission Regulation (EU) 601/2014 of 4/6/2014 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the food categories of meat and the use of certain food additives in meat preparations. TEXT with EEA relevance', 'Komisijos reglamentas (ES) 601/2014, 2014 m. birželio 4 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl mėsos maisto kategorijų ir tam tikrų maisto priedų naudojimo mėsos pusgaminiuose. Tekstas svarbus EEE', '(EU) No 0601/2014', NULL, NULL, NULL, 'L 166', '11');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (324915, 316516, 'Commission Regulation (EU) No 1093/2014 of 16/10/2014 amending and correcting Annex II of Regulation (EC) 1333/2008 of European Parliament and of the Council as regards the use of certain colours in flavoured ripened cheese. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1093/2014 2014 m. spalio 16 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų dažiklių naudojimo aromatizuotame brandintame sūryje. Tekstas svarbus EEE.', '(EU) No 1093/2014', NULL, NULL, NULL, 'L 299', '22');
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, scraped_at, translated_at) VALUES (365307, 'E160b(i)', 'E 160b(i)', 160, 'Annatto bixin', 'Anato biksinas', 'Annatto bixin', 'Anato biksinas', NULL, NULL, NULL, FALSE, NULL, 'POL-FAD-IMPORT-3379', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', '2026-04-07 08:30:54', '2026-04-07 12:05:56');
