INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_ML', '20', 'FAD_RU_MGK', 'only breakfast sausages with a minimum cereal content of 6 % and burger meat with a minimum vegetable and/or cereal content of 4 % mixed within the meat; In these products, the meat is minced in such a way so that the muscle and fat tissue are completely dispersed, so that fibre makes an emulsion with the fat, giving those products their typical appearance’', 'tik pusryčių dešrelės, kurių minimalus grūdų kiekis yra 6 %, ir faršo kotletai, kurių minimalus daržovių ir (arba) grūdų kiekis, sumaišytas su mėsa, yra 4 %; šiuose produktuose mėsa smulkinama taip, kad raumenų ir riebalų audiniai būtų visiškai išsklaidyti, todėl skaidulinės medžiagos sudaro emulsiją su riebalais, suteikdamos šiems produktams būdingą išvaizdą', '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315802', '8.3.1', 'Non-heat-treated processed meat', 'Termiškai neapdoroti perdirbti mėsos produktai', 'FAD_RT_ML', '20', 'FAD_RU_MGK', 'only chorizo sausage, salchichon, pasturmas and sobrasada’', 'tik chorizo dešra, salchichon, pasturmas ir sobrasada', '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315806', '8.3.2', 'Heat-treated processed meat', 'Termiškai apdorota perdirbta mėsa', 'FAD_RT_ML', '20', 'FAD_RU_MGK', 'only sausages, pâtés, terrines and luncheon meat’', 'tik dešrelės, paštetai, terinai ir šaltieji mėsos gaminiai', '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315810', '8.3.3', 'Casings and coatings and decorations for meat', 'Apvalkalai, dangalai ir mėsos dekoracijos', 'FAD_RT_ML', '50', 'FAD_RU_MGK', NULL, NULL, '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '10', 'FAD_RU_MGK', 'only smoked fish', 'tik rūkyta žuvis', '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
