INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '315938', '12.6', 'Sauces', 'Padažai', 'FAD_RT_ML', '30', 'FAD_RU_MGK', 'including pickles, relishes, chutney and piccalilli; excluding tomato-based sauces’', 'įskaitant marinuotus agurkus, prieskonius, čatnius ir pikalilius; išskyrus pomidorų padažus', '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '316082', '14.2.8', 'Other alcoholic beverages including mixtures of alcoholic beverages with non-alcoholic beverages and other alcoholic beverages based on distilled alcohol with alcoholic strength by volume less than 15 %', 'Kiti alkoholiniai gėrimai, įskaitant alkoholinių gėrimų mišinius su nealkoholiniais gėrimais ir kitus distiliuotu alkoholiu pagrindu pagamintus alkoholinius gėrimus, kurių faktinė alkoholio koncentracija tūrio procentais yra mažesnė nei 15 %', 'FAD_RT_ML', '10', 'FAD_RU_MGL', 'only alcoholic beverages with alcoholic strength by volume less than 15 %', 'tik alkoholiniai gėrimai, kurių alkoholio kiekis tūrio procentais yra mažesnis nei 15 %', NULL, NULL, NULL, 316896);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (365671, '316090', '15.1', 'Potato- cereal- flour- or starch-based snacks', 'Bulvių, grūdų, miltų arba krakmolo pagrindu pagaminti užkandžiai', 'FAD_RT_ML', '20', 'FAD_RU_MGK', NULL, NULL, '94', 'When E 160b(i) (Annatto bixin) and E 160b(ii) (Annatto norbixin) are added in combination, the higher individual maximum level applies to the sum, but the individual maximum levels shall not be exceeded.', 'Kai E 160b(i) (Anatų biksinas) ir E 160b(ii) (Anatų norbiksinas) dedami kartu, aukštesnis individualus didžiausias lygis taikomas jų sumai, tačiau individualių didžiausių lygių viršyti negalima.', 316896);
