INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (365671, 316896, 'COMMISSION REGULATION (EU) 2020/771 of 11 June 2020 amending Annexes II and III to Regulation (EC) No 1333/2008 of the European Parliament and of the Council and the Annex to Commission Regulation (EU) No 231/2012 as regards the use of Annatto, Bixin, Norbixin (E 160b) (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2020/771 2020 m. birželio 11 d., kuriuo iš dalies keičiami Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II ir III priedai ir Komisijos reglamento (ES) Nr. 231/2012 priedas, kiek tai susiję su anaто, biksino, norbiksino (E 160b) naudojimu (Tekstas svarbus EEE)', '(EU) No 2020/0771', NULL, NULL, NULL, 'L184', '25');
