INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (326467, '315622', '4.1.1', 'entire fresh fruit and vegetables', 'švieži neapdoroti vaisiai ir daržovės', 'FAD_RT_ML', '6', 'FAD_RU_MGK', 'only as a contrast enhancer for marking citrus fruit, melons and pomegranates in order to: &ndash; repeat all or some of the mandatory information particulars required by the Union legislation and/or national law, and/or &ndash; provide on a voluntary basis brand name, production method, PLU-code, QR-code and/or barcode', 'tik kaip kontrastą didinanti priemonė citrusiniams vaisiams, melionams ir granatams žymėti, siekiant: – pakartoti visas arba kai kurias privalomąsias informacijos nuorodas, kurių reikalaujama pagal Sąjungos teisės aktus ir (arba) nacionalinę teisę, ir (arba) – savanoriškai nurodyti prekės pavadinimą, gamybos būdą, PLU kodą, QR kodą ir (arba) brūkšninį kodą', NULL, NULL, NULL, 316326);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (326467, '315654', '4.2.4.1', 'fruit and vegetable preparations excluding compote', 'vaisių ir daržovių preparatai, išskyrus kompotą', 'FAD_RT_QS', NULL, NULL, 'only seaweed-based fish roe analogues', 'tik dumbliais pagrįsti žuvų ikrų analogai', NULL, NULL, NULL, 316386);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (326467, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_QS', NULL, NULL, 'only fish paste and crustacean paste', 'tik žuvies pasta ir vėžiagyvių pasta', NULL, NULL, NULL, 316636);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (326467, 316326, 'Commission Regulation (EU) 510/2013 of 3/6/2013 amendign Annex I, II and III to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of iron oxides and hydroxides (E172), hydroxypropyl methyl cellulose (E464) and polysorbates (E432-436) for making of certain fruits. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 510/2013, 2013 m. birželio 3 d., kuriuo iš dalies keičiami Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 I, II ir III priedai dėl geležies oksidų ir hidroksidų (E172), hidroksipropilmetilceliuliozės (E464) ir polisorbatų (E432–436) naudojimo tam tikrų vaisių apdorojimui. Tekstas svarbus EEE', '(EU) No 0510/2013', NULL, NULL, NULL, 'L 150', '17');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (326467, 316386, 'Commission Regulation (EU) 738/2013 of 30/07/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain additives in seaweed based fish roe analogues. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 738/2013, 2013 m. liepos 30 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų priedų naudojimo dumblių pagrindu pagamintuose žuvies ikrų analoguose. Tekstas svarbus EEE', '(EU) No 0738/2013', NULL, NULL, NULL, 'L 204', '32');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (326467, 316636, 'Commission Regulation (EU) 2015/647 of 24/04/2015 amending and correcting Annexes II and III to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/647, 2015 m. balandžio 24 d., kuriuo iš dalies keičiami ir taisomi Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II ir III priedai dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 2015/0647', NULL, NULL, NULL, '107', '1');
