INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (335298, '315962', '13.1.1', 'infant formulae as defined by Regulation (EU) No 609/2013', 'pradinės formulės, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '1000', 'FAD_RU_MGK', NULL, NULL, '14', 'If more than one of the substances E 322, E 471, E 472c and E 473 are added to a foodstuff, the maximum level established for that foodstuff for each of those substances is lowered with that relative part as is present of the other substances together in that foodstuff', 'Jeigu į maisto produktą dedama daugiau nei viena iš medžiagų E 322, E 471, E 472c ir E 473, tam maisto produktui nustatytas kiekvienos iš šių medžiagų didžiausias leistinas kiekis mažinamas ta santykine dalimi, kurią tame maisto produkte sudaro kitos medžiagos kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (335298, '315966', '13.1.2', 'follow-on formulae as defined by by Regulation (EU) No 609/2013', 'tolesnio maitinimo formulės, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '1000', 'FAD_RU_MGK', NULL, NULL, '14', 'If more than one of the substances E 322, E 471, E 472c and E 473 are added to a foodstuff, the maximum level established for that foodstuff for each of those substances is lowered with that relative part as is present of the other substances together in that foodstuff', 'Jeigu į maisto produktą dedama daugiau nei viena iš medžiagų E 322, E 471, E 472c ir E 473, tam maisto produktui nustatytas kiekvienos iš šių medžiagų didžiausias leistinas kiekis mažinamas ta santykine dalimi, kurią tame maisto produkte sudaro kitos medžiagos kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (335298, '315970', '13.1.3', 'Processed cereal-based foods and baby foods as defined by Regulation (EU) No 609/2013', 'Perdirbtų grūdų pagrindu pagaminti maisto produktai ir kūdikių maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '10000', 'FAD_RU_MGK', 'only biscuits and rusks, cereal-based foods, baby foods', 'tik sausainiai ir džiūvėsiai, grūdų pagrindu pagaminti maisto produktai, kūdikių maistas', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (335298, '315958', '13.1', 'foods for infants and young children', 'maisto produktai kūdikiams ir mažiems vaikams', NULL, NULL, NULL, 'For uses in nutrient preparations under the condition that the maximum level in foods mentioned in Part E, points 01.10 and 13.1, of Annex II is not exceeded', 'Naudojimui maistingųjų medžiagų preparatuose su sąlyga, kad neviršijamas II priedo E dalyje, 01.10 ir 13.1 punktuose nurodytuose maisto produktuose nustatytas didžiausias leistinas kiekis', NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (335298, '2696131', '1.10', 'Milk-based drinks and similar products intended for young children*', 'Pieno pagrindu pagaminti gėrimai ir panašūs produktai, skirti mažiems vaikams*', 'FAD_RT_ML', '10000', 'FAD_RU_MGL', NULL, NULL, NULL, NULL, NULL, NULL);
