INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (336277, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_QS', NULL, NULL, 'only gehakt, prepacked preparations of fresh minced meat and meat preparations to which other ingredients than additives or salt have been added', 'tik gehakt, iš anksto supakuoti šviežios maltos mėsos preparatai ir mėsos preparatai, į kuriuos buvo pridėta kitų ingredientų, nei priedai ar druska', NULL, NULL, NULL, 316356);
