INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (336624, '315970', '13.1.3', 'Processed cereal-based foods and baby foods as defined by Regulation (EU) No 609/2013', 'Perdirbtų grūdų pagrindu pagaminti maisto produktai ir kūdikių maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_QS', NULL, NULL, 'only processed cereal based foods and baby foods, only for pH adjustment', 'tik perdirbtų javų pagrindu pagaminti maisto produktai ir kūdikių maistas, tik pH reguliavimui', NULL, NULL, NULL, 316526);
