INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (339986, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '15', 'FAD_RU_MGK', 'only fish and fishery products including molluscs and crustaceans with a fat content not higher than 10%', 'tik žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius, kurių riebalų kiekis ne didesnis kaip 10 %', '41', 'Expressed on fat basis', 'Išreikšta riebalų atžvilgiu', 316376);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (339986, '315654', '4.2.4.1', 'fruit and vegetable preparations excluding compote', 'vaisių ir daržovių preparatai, išskyrus kompotą', 'FAD_RT_ML', '200', 'FAD_RU_MGK', 'only seaweed-based fish roe analogues', 'tik dumbliais pagrįsti žuvų ikrų analogai', '46', 'As the sum of carnosol and carnosic acid', 'Kaip karnosolio ir karnosinės rūgšties suma', 316386);
