INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (339986, '315802', '8.3.1', 'Non-heat-treated processed meat', 'Termiškai neapdoroti perdirbti mėsos produktai', 'FAD_RT_ML', '15', 'FAD_RU_MGK', 'only meat with a fat content not higher than 10%, excluding dried sausages', 'tik mėsa, kurios riebalų kiekis ne didesnis nei 10 %, išskyrus džiovintas dešras', '41', 'Expressed on fat basis', 'Išreikšta riebalų atžvilgiu', 316376);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (339986, '315806', '8.3.2', 'Heat-treated processed meat', 'Termiškai apdorota perdirbta mėsa', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only meat with a fat content higher than 10%, excluding dried sausages', 'tik mėsa, kurios riebalų kiekis didesnis nei 10 %, išskyrus džiovintas dešras', '41', 'Expressed on fat basis', 'Išreikšta riebalų atžvilgiu', 316376);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (339986, '2696141', '2.2.2', 'Other fat and oil emulsions including spreads as defined by Regulation (EC) No 1234/2007 and liquid emulsions', 'Kitos riebalų ir aliejų emulsijos, įskaitant tepius produktus, kaip apibrėžta Reglamente (EB) Nr. 1234/2007, ir skystąsias emulsijas', 'FAD_RT_ML', '100', 'FAD_RU_MGK', 'only spreadable fats with a fat content less than 80 %’', 'tik tepieji riebalai, kurių riebalų kiekis mažesnis nei 80 %''', '41', 'Expressed on fat basis', 'Išreikšta riebalų atžvilgiu', 316766);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (339986, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (339986, 316566, 'Commission Regulation (EU) No 1149/2012 of 4/12/2012 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of extracts of rosemary (E392) in fillings of stuffed dried pasta. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1149/2012 2012 m. gruodžio 4 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl rozmarinų ekstraktų (E392) naudojimo įdarytų džiovintų makaronų įdare. Tekstas svarbus EEE.', '(EU) No 1149/2012', NULL, NULL, NULL, 'L 333', '40');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (339986, 316376, 'Commission Regulation (EU) 723/2013 of 26/07/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of extracts of Rosemary (E392) in certain low fat meatand fish products. TEXT with EEA relevance', 'Komisijos reglamentas (ES) 723/2013, 2013 m. liepos 26 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl rozmarino ekstraktų (E392) naudojimo tam tikruose mažai riebalų turinčiuose mėsos ir žuvies produktuose. Tekstas svarbus EEE', '(EU) No 0723/2013', NULL, NULL, NULL, 'L 202', '8');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (339986, 316386, 'Commission Regulation (EU) 738/2013 of 30/07/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain additives in seaweed based fish roe analogues. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 738/2013, 2013 m. liepos 30 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų priedų naudojimo dumblių pagrindu pagamintuose žuvies ikrų analoguose. Tekstas svarbus EEE', '(EU) No 0738/2013', NULL, NULL, NULL, 'L 204', '32');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (339986, 316766, 'COMMISSION REGULATION (EU) 2016/56 of 19 January 2016 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of extracts of rosemary (E 392) in spreadable fats', 'KOMISIJOS REGLAMENTAS (ES) 2016/56 2016 m. sausio 19 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl rozmarinų ekstraktų (E 392) naudojimo tepiosiose riebaluose', '(EU) No 2016/56', NULL, NULL, NULL, '31', '46');
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, scraped_at, translated_at) VALUES (340464, 'E400', 'E 400', 400, 'Alginic acid', 'Alginų rūgštis', 'Alginic acid', 'Alginų rūgštis', NULL, NULL, NULL, FALSE, 'POL-FAD-IMPORT-2981', 'POL-FAD-IMPORT-3126', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', '2026-04-07 08:31:19', '2026-04-07 12:05:56');
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (340464, '315970', '13.1.3', 'Processed cereal-based foods and baby foods as defined by Regulation (EU) No 609/2013', 'Perdirbtų grūdų pagrindu pagaminti maisto produktai ir kūdikių maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '500', 'FAD_RU_MGK', 'only desserts and puddings', 'tik desertai ir pudingai', '23', 'E 400, E 401, E 402 and E 404 are authorised individually or in combination', 'E 400, E 401, E 402 ir E 404 leidžiami naudoti atskirai arba kartu', 316526);
