INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (340579, '315626', '4.1.2', 'peeled cut and shredded fruit and vegetables', 'nulupti, supjaustyti ir susmulkinti vaisiai ir daržovės', 'FAD_RT_ML', '2400', NULL, 'only prepacked refrigerated unproccessed fruit and vegetables ready for consumption, to be sold to the final consumer', 'tik iš anksto supakuoti atšaldyti neapdoroti vaisiai ir daržovės, paruošti vartoti, parduodami galutiniam vartotojui', '82', 'May only be used in combination with E 302 as glazing agents and with a maximum level of 800 mg/kg of E 302 in the final food', 'Gali būti naudojama tik kartu su E 302 kaip glazūravimo medžiagos, o maksimalus E 302 kiekis galutiniame maisto produkte yra 800 mg/kg', 316436);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (340579, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_QS', NULL, NULL, 'only preparations in which ingredients have been injected; meat preparations composed of meat parts that have been handled differently: minced, sliced or processed and that are combined together. Except bifteki, soutzoukaki, kebap gyros and souvlaki', 'tik pusgaminiai, į kuriuos ingredientai buvo įšvirkšti; mėsos pusgaminiai, sudaryti iš skirtingai apdorotų mėsos dalių: maltų, pjaustytų arba perdirbtų ir sujungtų kartu. Išskyrus bifteki, soutzoukaki, kebap, gyros ir souvlaki', NULL, NULL, NULL, 316356);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (340579, '315970', '13.1.3', 'Processed cereal-based foods and baby foods as defined by Regulation (EU) No 609/2013', 'Perdirbtų grūdų pagrindu pagaminti maisto produktai ir kūdikių maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '500', 'FAD_RU_MGK', 'only desserts and puddings', 'tik desertai ir pudingai', '23', 'E 400, E 401, E 402 and E 404 are authorised individually or in combination', 'E 400, E 401, E 402 ir E 404 leidžiami naudoti atskirai arba kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (340579, '13.1.3.1. Foods for special medical purposes, as defined by Regulation (EU) No 609/2013, intended for infants', NULL, NULL, NULL, 'FAD_RT_ML', '1000', 'FAD_RU_MGK', 'from four months onwards in special food products with adapted composition, required for metabolic disorders and for general tube-feeding', 'nuo keturių mėnesių specialiuosiuose maisto produktuose su pritaikyta sudėtimi, reikalinguose medžiagų apykaitos sutrikimams ir bendrajam maitinimui per zondą', NULL, NULL, NULL, 316526);
