INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (341490, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_QS', NULL, NULL, 'only preparations in which ingredients have been injected; meat preparations composed of meat parts that have been handled differently: minced, sliced or processed and that are combined together. Except bifteki, soutzoukaki, kebap gyros and souvlaki', 'tik pusgaminiai, į kuriuos ingredientai buvo įšvirkšti; mėsos pusgaminiai, sudaryti iš skirtingai apdorotų mėsos dalių: maltų, pjaustytų arba perdirbtų ir sujungtų kartu. Išskyrus bifteki, soutzoukaki, kebap, gyros ir souvlaki', NULL, NULL, NULL, 316356);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (341490, 316356, 'Commission Regulation (EU) 601/2014 of 4/6/2014 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the food categories of meat and the use of certain food additives in meat preparations. TEXT with EEA relevance', 'Komisijos reglamentas (ES) 601/2014, 2014 m. birželio 4 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl mėsos maisto kategorijų ir tam tikrų maisto priedų naudojimo mėsos pusgaminiuose. Tekstas svarbus EEE', '(EU) No 0601/2014', NULL, NULL, NULL, 'L 166', '11');
