INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (341537, '315662', '4.2.5', 'jam jellies and marmalades and similar products', 'uogienės, želė, marmeladai ir panašūs produktai', 'FAD_RT_ML', '10000', 'FAD_RU_MGK', NULL, NULL, '32', 'Maximum individually or in combination with E 400 - 404, E 406, E 407, E 410, E 412, E 415 and E 418', 'Didžiausia riba atskirai arba derinyje su E 400–404, E 406, E 407, E 410, E 412, E 415 ir E 418', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (341537, '315674', '4.2.5.3', 'other similar fruit or vegetable spreads', 'kiti panašūs vaisių arba daržovių tepiniai', 'FAD_RT_ML', '10000', 'FAD_RU_MGK', NULL, NULL, '32', 'Maximum individually or in combination with E 400 - 404, E 406, E 407, E 410, E 412, E 415 and E 418', 'Didžiausia riba atskirai arba derinyje su E 400–404, E 406, E 407, E 410, E 412, E 415 ir E 418', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (341537, '315966', '13.1.2', 'follow-on formulae as defined by by Regulation (EU) No 609/2013', 'tolesnio maitinimo formulės, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '1000', 'FAD_RU_MGK', NULL, NULL, '17', 'If more than one of the substances E 407, E 410 and E 412 is added to a foodstuff, the maximum level established for that foodstuff for each of those substances is lowered with that relative part as is present of the other substances together in that foodstuff', 'Jeigu į maisto produktą dedama daugiau nei viena iš medžiagų E 407, E 410 ir E 412, tam maisto produktui nustatytas kiekvienos iš šių medžiagų didžiausias leistinas kiekis mažinamas ta santykine dalimi, kurią tame maisto produkte sudaro kitos medžiagos kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (341537, '315970', '13.1.3', 'Processed cereal-based foods and baby foods as defined by Regulation (EU) No 609/2013', 'Perdirbtų grūdų pagrindu pagaminti maisto produktai ir kūdikių maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '10000', 'FAD_RU_MGK', 'only processed cereal based foods and baby foods', 'tik perdirbtų javų pagrindu pagaminti maisto produktai ir kūdikių maistas', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (341537, '2747592', '13.1.5.1', 'Foods for special medical purposes as defined by Regulation (EU) No 609/2013, intended for infants', 'Specialiosios medicininės paskirties maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013, skirtas kūdikiams', 'FAD_RT_ML', '5300', 'FAD_RU_MGK', 'From birth onwards in products for reduction of gastro-oesophageal reflux', 'Nuo gimimo produktuose, skirtuose gastroezofaginio refliukso mažinimui', NULL, NULL, NULL, 316526);
