INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315742', '6.4.3', 'Fresh pre-cooked pasta', 'Šviežiai iš anksto virti makaronų gaminiai', 'FAD_RT_QS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315774', '7.1.1', 'Bread prepared solely with the following ingredients: wheat flour, water, yeast or leaven, salt', 'Duona, gaminama tik iš šių ingredientų: kviečių miltų, vandens, mielių arba raugo, druskos', 'FAD_RT_QS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 316526);
