INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315894', '11.4.3', 'table-top sweeteners in tablets', 'stalo saldikliai tabletėmis', 'FAD_RT_QS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315590', '2.1', 'fats and oils essentially free from water (excluding anhydrous milk fat)', 'riebalai ir aliejai, iš esmės neturintys vandens (išskyrus bevandenį pieno riebalą)', 'FAD_RT_ML', '10000', 'FAD_RU_MGK', 'except virgin oils and olive oils', 'išskyrus nerafinuotus aliejus ir alyvuogių aliejus', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315762', '6.7', 'pre-cooked or processed cereals', 'iš anksto virti arba perdirbti grūdai', 'FAD_RT_QS', NULL, NULL, 'only quick-cook rice', 'tik greitai verdantys ryžiai', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315962', '13.1.1', 'infant formulae as defined by Regulation (EU) No 609/2013', 'pradinės formulės, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '4000', 'FAD_RU_MGK', NULL, NULL, '14', 'If more than one of the substances E 322, E 471, E 472c and E 473 are added to a foodstuff, the maximum level established for that foodstuff for each of those substances is lowered with that relative part as is present of the other substances together in that foodstuff', 'Jeigu į maisto produktą dedama daugiau nei viena iš medžiagų E 322, E 471, E 472c ir E 473, tam maisto produktui nustatytas kiekvienos iš šių medžiagų didžiausias leistinas kiekis mažinamas ta santykine dalimi, kurią tame maisto produkte sudaro kitos medžiagos kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315966', '13.1.2', 'follow-on formulae as defined by by Regulation (EU) No 609/2013', 'tolesnio maitinimo formulės, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '4000', 'FAD_RU_MGK', NULL, NULL, '14', 'If more than one of the substances E 322, E 471, E 472c and E 473 are added to a foodstuff, the maximum level established for that foodstuff for each of those substances is lowered with that relative part as is present of the other substances together in that foodstuff', 'Jeigu į maisto produktą dedama daugiau nei viena iš medžiagų E 322, E 471, E 472c ir E 473, tam maisto produktui nustatytas kiekvienos iš šių medžiagų didžiausias leistinas kiekis mažinamas ta santykine dalimi, kurią tame maisto produkte sudaro kitos medžiagos kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315970', '13.1.3', 'Processed cereal-based foods and baby foods as defined by Regulation (EU) No 609/2013', 'Perdirbtų grūdų pagrindu pagaminti maisto produktai ir kūdikių maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '5000', 'FAD_RU_MGK', 'only biscuits and rusks, cereal-based foods, baby foods', 'tik sausainiai ir džiūvėsiai, grūdų pagrindu pagaminti maisto produktai, kūdikių maistas', '22', 'E 471, E 472a, E 472b and E 472c are authorised individually or in combination', 'E 471, E 472a, E 472b ir E 472c leidžiami naudoti atskirai arba kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315746', '6.4.4', 'Gnocchi', 'Gnokai', 'FAD_RT_QS', NULL, NULL, 'only fresh refrigerated potato gnocchi', 'tik švieži šaldytuve laikomi bulvių gnokai', NULL, NULL, NULL, 316636);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '13.1.3.1. Foods for special medical purposes, as defined by Regulation (EU) No 609/2013, intended for infants', NULL, NULL, NULL, 'FAD_RT_ML', '5000', 'FAD_RU_MGK', 'from birth onwards in specialised diets, particularly those devoid of proteins', 'nuo gimimo specialiosiose dietose, ypač tose, kuriose nėra baltymų', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '13.1.3.2. Foods for special medical purposes, as defined by Regulation (EU) No 609/2013, intended for infants as from four months of age and for young children', NULL, NULL, NULL, 'FAD_RT_ML', '5000', 'FAD_RU_MGK', 'from birth onwards in specialised diets, particularly those devoid of proteins', 'nuo gimimo specialiosiose dietose, ypač tose, kuriose nėra baltymų', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315622', '4.1.1', 'entire fresh fruit and vegetables', 'švieži neapdoroti vaisiai ir daržovės', 'FAD_RT_QS', NULL, NULL, 'only for the surface treatment of citrus fruit, melons, pineapples, bananas, papayas, mangoes, avocados, pomegranates, passion fruit, kiwis and cassavas’', 'tik citrinų vaisių, melionų, ananasų, bananų, papajų, mangų, avokadų, granatų, pasiflorų vaisių, kivių ir kasavų paviršiaus apdorojimui', NULL, NULL, NULL, 316876);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '315958', '13.1', 'foods for infants and young children', 'maisto produktai kūdikiams ir mažiems vaikams', NULL, NULL, NULL, 'For uses in nutrient preparations under the condition that the maximum level in foods mentioned in Part E, points 01.10 and 13.1, of Annex II is not exceeded and the conditions of use specified therein are respected', 'Naudojimui maistingųjų medžiagų preparatuose su sąlyga, kad neviršijamas II priedo E dalyje, 01.10 ir 13.1 punktuose nurodytuose maisto produktuose nustatytas didžiausias leistinas kiekis ir laikomasi joje nurodytų naudojimo sąlygų', NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345369, '2696131', '1.10', 'Milk-based drinks and similar products intended for young children*', 'Pieno pagrindu pagaminti gėrimai ir panašūs produktai, skirti mažiems vaikams*', 'FAD_RT_ML', '4000', 'FAD_RU_MGL', NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (345369, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (345369, 316636, 'Commission Regulation (EU) 2015/647 of 24/04/2015 amending and correcting Annexes II and III to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/647, 2015 m. balandžio 24 d., kuriuo iš dalies keičiami ir taisomi Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II ir III priedai dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 2015/0647', NULL, NULL, NULL, '107', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (345369, 316876, 'Commission Regulation (EU) 2019/801 of 17 May 2019 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of mono- and diglycerides of fatty acids (E 471) on certain fresh fruits (Text with EEA relevance.)', 'Komisijos reglamentas (ES) 2019/801, 2019 m. gegužės 17 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl mono- ir digliceridų (E 471) naudojimo ant tam tikrų šviežių vaisių. (Tekstas svarbus EEE)', '(EU) No 2019/0801', NULL, NULL, NULL, '132', '18');
