INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345814, '315970', '13.1.3', 'Processed cereal-based foods and baby foods as defined by Regulation (EU) No 609/2013', 'Perdirbtų grūdų pagrindu pagaminti maisto produktai ir kūdikių maistas, kaip apibrėžta Reglamente (ES) Nr. 609/2013', 'FAD_RT_ML', '5000', 'FAD_RU_MGK', 'only biscuits and rusks, cereal-based foods, baby foods', 'tik sausainiai ir džiūvėsiai, grūdų pagrindu pagaminti maisto produktai, kūdikių maistas', '22', 'E 471, E 472a, E 472b and E 472c are authorised individually or in combination', 'E 471, E 472a, E 472b ir E 472c leidžiami naudoti atskirai arba kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345814, '13.1.3.1. Foods for special medical purposes, as defined by Regulation (EU) No 609/2013, intended for infants', NULL, NULL, NULL, 'FAD_RT_ML', '7500', 'FAD_RU_MGK', 'only when sold as powder; From birth onwards', 'tik kai parduodama kaip milteliai; Nuo gimimo', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345814, '13.1.3.2. Foods for special medical purposes, as defined by Regulation (EU) No 609/2013, intended for infants as from four months of age and for young children', NULL, NULL, NULL, 'FAD_RT_ML', '7500', 'FAD_RU_MGK', 'only when sold as powder; From birth onwards', 'tik kai parduodama kaip milteliai; Nuo gimimo', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345814, '315590', '2.1', 'fats and oils essentially free from water (excluding anhydrous milk fat)', 'riebalai ir aliejai, iš esmės neturintys vandens (išskyrus bevandenį pieno riebalą)', 'FAD_RT_QS', NULL, NULL, 'only for cooking and/or frying purposes or for the preparation of gravy, except virgin oils and olive oils', 'tik virimui ir (arba) kepimui aliejuje arba padažo ruošimui, išskyrus nerafinuotus aliejus ir alyvuogių aliejus', NULL, NULL, NULL, 316636);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (345814, '2696131', '1.10', 'Milk-based drinks and similar products intended for young children*', 'Pieno pagrindu pagaminti gėrimai ir panašūs produktai, skirti mažiems vaikams*', 'FAD_RT_ML', '7500', 'FAD_RU_MGL', 'only when sold as powder', 'tik kai parduodama kaip milteliai', NULL, NULL, NULL, NULL);
