INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (356062, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (356062, 316386, 'Commission Regulation (EU) 738/2013 of 30/07/2013 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain additives in seaweed based fish roe analogues. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 738/2013, 2013 m. liepos 30 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų priedų naudojimo dumblių pagrindu pagamintuose žuvies ikrų analoguose. Tekstas svarbus EEE', '(EU) No 0738/2013', NULL, NULL, NULL, 'L 204', '32');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (356062, 316146, 'COMMISSION REGULATION (EU) 2018/97 of 22 January 2018 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of sweeteners in fine bakery wares (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2018/97 2018 m. sausio 22 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl saldiklių naudojimo smulkiuose kepiniuose. (Tekstas svarbus EEE)', ' (EU) No 2018/0097', NULL, NULL, NULL, 'L 17', '11');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (356062, 316856, 'COMMISSION REGULATION (EU) 2018/1497 of 8 October 2018 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards food category 17 and the use of food additives in food supplements (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2018/1497 2018 m. spalio 8 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl 17 maisto kategorijos ir maisto priedų naudojimo maisto papilduose. (Tekstas svarbus EEE)', '(EU) No 2018/1497', NULL, NULL, NULL, 'L 253', '36');
