INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (356625, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
