INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (358084, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (358084, 316506, 'COMMISSION REGULATION (EU) No 1092/2014 of 16 October 2014 amending Annex II to Regulation (EC) No 1333/2008 of European Parliament and of the Council as regards the use of sweeteners in certain fruit or vegetable spreads TEXT with EEA relevance', 'KOMISIJOS REGLAMENTAS (ES) Nr. 1092/2014 2014 m. spalio 16 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas, kiek tai susiję su saldiklių naudojimu tam tikruose vaisių arba daržovių tepuose (Tekstas svarbus EEE)', '(EU) No 1092/2014', NULL, NULL, NULL, 'L 299', '19');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (358084, 316636, 'Commission Regulation (EU) 2015/647 of 24/04/2015 amending and correcting Annexes II and III to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/647, 2015 m. balandžio 24 d., kuriuo iš dalies keičiami ir taisomi Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II ir III priedai dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 2015/0647', NULL, NULL, NULL, '107', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (358084, 316146, 'COMMISSION REGULATION (EU) 2018/97 of 22 January 2018 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of sweeteners in fine bakery wares (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2018/97 2018 m. sausio 22 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl saldiklių naudojimo smulkiuose kepiniuose. (Tekstas svarbus EEE)', ' (EU) No 2018/0097', NULL, NULL, NULL, 'L 17', '11');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (358084, 316856, 'COMMISSION REGULATION (EU) 2018/1497 of 8 October 2018 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards food category 17 and the use of food additives in food supplements (Text with EEA relevance)', 'KOMISIJOS REGLAMENTAS (ES) 2018/1497 2018 m. spalio 8 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl 17 maisto kategorijos ir maisto priedų naudojimo maisto papilduose. (Tekstas svarbus EEE)', '(EU) No 2018/1497', NULL, NULL, NULL, 'L 253', '36');
