INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (358736, '315674', '4.2.5.3', 'other similar fruit or vegetable spreads', 'kiti panašūs vaisių arba daržovių tepiniai', 'FAD_RT_ML', '1000', 'FAD_RU_MGK', 'only energy-reduced fruit or vegetable spreads and dried-fruit-based sandwich spreads, energy-reduced or with no added sugar', 'tik sumažintos energinės vertės vaisių arba daržovių tepiniai ir sumuštiniams skirti džiovintų vaisių pagrindu pagaminti tepiniai, sumažintos energinės vertės arba be pridėtinio cukraus', '49', 'The maximum usable levels are derived from the maximum usable levels for its constituent parts, aspartame (E 951) and acesulfame-K (E 950)', 'Didžiausias leistinas naudojimo lygis apskaičiuojamas pagal didžiausius leidžiamus jo sudedamųjų dalių – aspartamo (E 951) ir acesulfamo K (E 950) – naudojimo lygius', 316506);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (358736, '315526', '1.4', 'flavoured fermented milk products including heat-treated products', 'aromatizuoti fermentuoto pieno produktai, įskaitant termiškai apdorotus produktus', 'FAD_RT_ML', '350', 'FAD_RU_MGL', 'only energy-reduced products or with no added sugar', 'tik sumažintos energinės vertės produktai arba be pridėtinio cukraus', '11(a)', 'Limits are expressed as acesulfame K equivalent', 'Ribos išreikštos acesulfamo K ekvivalentu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (358736, '315702', '5.4', 'Decorations, coatings and fillings, except fruit-based fillings covered by category 4.2.4', 'Dekoracijos, dangos ir įdarai, išskyrus vaisių pagrindu pagamintus įdarus, kuriems taikoma kategorija 4.2.4', 'FAD_RT_ML', '350', 'FAD_RU_MGK', 'only sauces', 'tik padažai', '11(a)', 'Limits are expressed as acesulfame K equivalent', 'Ribos išreikštos acesulfamo K ekvivalentu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (358736, '316042', '14.2.1', 'beer and malt beverages', 'alus ir salyklo gėrimai', 'FAD_RT_ML', '350', 'FAD_RU_MGL', 'only alcohol-free beer or with an alcohol content not exceeding 1,2 % vol; ''Bi&egrave;re de table/Tafelbier/Table beer'' (original wort content less than 6 %) except for ''Oberg&auml;riges Einfachbier''; Beers with a minimum acidity of 30 milli-equivalents expressed as NaOH; Brown beers of the ''oud bruin'' type', 'tik nealkoholinis alus arba alus, kurio alkoholio kiekis neviršija 1,2 % tūrio; „Bière de table/Tafelbier/Table beer" (pradinio salyklo kiekis mažiau nei 6 %), išskyrus „Obergäriges Einfachbier"; alus, kurio minimalus rūgštingumas yra 30 miliekvivalentų, išreikštas kaip NaOH; tamsus alus „oud bruin" tipo', '11(a)', 'Limits are expressed as acesulfame K equivalent', 'Ribos išreikštos acesulfamo K ekvivalentu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (358736, '315782', '7.2', 'Fine bakery wares', 'Smulkūs kepiniai', 'FAD_RT_ML', '1000', 'FAD_RU_MGK', 'only essoblaten - wafer paper', 'tik essoblaten – vaflinį popierių', '49', 'The maximum usable levels are derived from the maximum usable levels for its constituent parts, aspartame (E 951) and acesulfame-K (E 950)', 'Didžiausias leistinas naudojimo lygis apskaičiuojamas pagal didžiausius leidžiamus jo sudedamųjų dalių – aspartamo (E 951) ir acesulfamo K (E 950) – naudojimo lygius', 316146);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (358736, '316106', '17.1', 'food supplements supplied in a solid form excluding food supplements for infants and young children’,', 'maisto papildai, tiekiami kietos formos, išskyrus maisto papildus kūdikiams ir mažiems vaikams', 'FAD_RT_ML', '500', 'FAD_RU_MGK', NULL, NULL, '11(a)', 'Limits are expressed as acesulfame K equivalent', 'Ribos išreikštos acesulfamo K ekvivalentu', 316856);
