INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (359691, '2747789', '14.1.4', 'Flavoured_drinks', 'Aromatizuoti gėrimai', 'FAD_RT_ML', '16000', 'FAD_RU_MGL', 'only energy-reduced or with no added sugars, as flavour enhancer only', 'tik sumažintos energinės vertės arba be pridėtinių cukrų, tik kaip skonio stipriklis', NULL, NULL, NULL, 316696);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (359691, 316696, 'COMMISSION REGULATION (EU) 2015/1832 of 12 October 2015 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of Erythritol (E968) as a flavour enhancer in energy-reduced or with no added sugars flavoured drinks. TEXT with EEA relevance', 'KOMISIJOS REGLAMENTAS (ES) 2015/1832 2015 m. spalio 12 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl eritriolio (E 968) naudojimo kaip skonio stipriklio sumažinto energetingumo arba be pridėtinio cukraus aromatizuotuose gėrimuose. Tekstas svarbus EEE', '(EU) No 2015/1832', NULL, NULL, NULL, 'L266', '28');
