INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '315782', '7.2', 'Fine bakery wares', 'Smulkūs kepiniai', 'FAD_RT_ML', '50', 'FAD_RU_MGK', 'only dry biscuits', 'tik sausi sausainiai', '3', 'Maximum levels are expressed as SO2 and relate to the total quantity, available from all sources, an SO2 content of not more than 10 mg/kg or 10 mg/l is not considered to be present', 'Didžiausias lygis išreikštas SO2 ir susijęs su bendru kiekiu iš visų šaltinių; SO2 kiekis, neviršijantis 10 mg/kg arba 10 mg/l, nelaikomas esamu', 316636);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '50', 'FAD_RU_MGK', 'only cooked crustaceans and cephalopods', 'tik virti vėžiagyviai ir galvakojiai moliuskai', '3', 'Maximum levels are expressed as SO2 and relate to the total quantity, available from all sources, an SO2 content of not more than 10 mg/kg or 10 mg/l is not considered to be present', 'Didžiausias lygis išreikštas SO2 ir susijęs su bendru kiekiu iš visų šaltinių; SO2 kiekis, neviršijantis 10 mg/kg arba 10 mg/l, nelaikomas esamu', 316636);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '316082', '14.2.8', 'Other alcoholic beverages including mixtures of alcoholic beverages with non-alcoholic beverages and other alcoholic beverages based on distilled alcohol with alcoholic strength by volume less than 15 %', 'Kiti alkoholiniai gėrimai, įskaitant alkoholinių gėrimų mišinius su nealkoholiniais gėrimais ir kitus distiliuotu alkoholiu pagrindu pagamintus alkoholinius gėrimus, kurių faktinė alkoholio koncentracija tūrio procentais yra mažesnė nei 15 %', 'FAD_RT_ML', '200', 'FAD_RU_MGL', 'only napój winny owocowy, napój winny miodowy, aromatyzowany napój winny owocowy, aromatyzowany napój winny miodowy,', 'tik napój winny owocowy, napój winny miodowy, aromatyzowany napój winny owocowy, aromatyzowany napój winny miodowy,', '3', 'Maximum levels are expressed as SO2 and relate to the total quantity, available from all sources, an SO2 content of not more than 10 mg/kg or 10 mg/l is not considered to be present', 'Didžiausias lygis išreikštas SO2 ir susijęs su bendru kiekiu iš visų šaltinių; SO2 kiekis, neviršijantis 10 mg/kg arba 10 mg/l, nelaikomas esamu', 316556);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '315842', '9.1.2', 'Unprocessed molluscs and crustaceans', 'Neapdoroti moliuskai ir vėžiagyviai', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only fresh, frozen and deep-frozen crustaceans and cephalopods; crustaceans of the Penaeidae, Solenoceridae and Aristaeidae family up to 80 units per kg', 'tik švieži, šaldyti ir giliai užšaldyti vėžiagyviai ir galvakojiai moliuskai; Penaeidae, Solenoceridae ir Aristaeidae šeimos vėžiagyviai – iki 80 vienetų kilogramui', '3', 'Maximum levels are expressed as SO2 and relate to the total quantity, available from all sources, an SO2 content of not more than 10 mg/kg or 10 mg/l is not considered to be present', 'Didžiausias lygis išreikštas SO2 ir susijęs su bendru kiekiu iš visų šaltinių; SO2 kiekis, neviršijantis 10 mg/kg arba 10 mg/l, nelaikomas esamu', 316636);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '316070', '14.2.7.1', 'Aromatised wines', 'Aromatizuoti vynai', 'FAD_RT_ML', '200', 'FAD_RU_MGL', NULL, NULL, '3', 'Maximum levels are expressed as SO2 and relate to the total quantity, available from all sources, an SO2 content of not more than 10 mg/kg or 10 mg/l is not considered to be present', 'Didžiausias lygis išreikštas SO2 ir susijęs su bendru kiekiu iš visų šaltinių; SO2 kiekis, neviršijantis 10 mg/kg arba 10 mg/l, nelaikomas esamu', 316216);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '316074', '14.2.7.2', 'Aromatised wine-based drinks', 'Aromatizuoti vyno pagrindu gaminami gėrimai', 'FAD_RT_ML', '200', 'FAD_RU_MGL', NULL, NULL, '3', 'Maximum levels are expressed as SO2 and relate to the total quantity, available from all sources, an SO2 content of not more than 10 mg/kg or 10 mg/l is not considered to be present', 'Didžiausias lygis išreikštas SO2 ir susijęs su bendru kiekiu iš visų šaltinių; SO2 kiekis, neviršijantis 10 mg/kg arba 10 mg/l, nelaikomas esamu', 316216);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '316078', '14.2.7.3', 'Aromatised wine-product cocktails', 'Aromatizuotų vyno produktų kokteiliai', 'FAD_RT_ML', '200', 'FAD_RU_MGL', NULL, NULL, '3', 'Maximum levels are expressed as SO2 and relate to the total quantity, available from all sources, an SO2 content of not more than 10 mg/kg or 10 mg/l is not considered to be present', 'Didžiausias lygis išreikštas SO2 ir susijęs su bendru kiekiu iš visų šaltinių; SO2 kiekis, neviršijantis 10 mg/kg arba 10 mg/l, nelaikomas esamu', 316216);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '2747789', '14.1.4', 'Flavoured_drinks', 'Aromatizuoti gėrimai', 'FAD_RT_ML', '20', 'FAD_RU_MGL', 'only carry over from concentrates in non-alcoholic flavoured drinks containing fruit juice', 'tik pernešimas iš koncentratų nealkoholiniuose aromatintuose gėrimuose, kurių sudėtyje yra vaisių sulčių', NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (329212, '2747794', '14.1.2', 'Fruit juices as defined by Directive 2001/112/EC and vegetable juices', 'Vaisių sultys, kaip apibrėžta Direktyvoje 2001/112/EB, ir daržovių sultys', 'FAD_RT_ML', '2000', 'FAD_RU_MGL', 'only concentrated grape juice for home wine-making', 'tik koncentruotos vynuogių sultys namų vyno gamybai', NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (329212, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (329212, 316556, 'Commission Regulation (EU) 1148/2012 of 4/12/2012 amending Annex II to Regulation 1333/2008 of the European Parliament and of the Council as regards the use of sulphur dioxide, sulphites (E 220-228) and propane 1,2-diol alginate (E-405) in fermented grape must-based drinks. TEXT with EEA relevance', 'Komisijos reglamentas (ES) 1148/2012, 2012 m. gruodžio 4 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento 1333/2008 II priedas dėl sieros dioksido, sulfitų (E 220–228) ir propano-1,2-diolio alginato (E-405) naudojimo fermentuotuose vynuogių mistos pagrindu pagamintuose gėrimuose. Tekstas svarbus EEE', '(EU) No 1148/2012', NULL, NULL, NULL, 'L 333', '37');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (329212, 316216, 'Commission Regulation (EU) 59/2014 of 23/01/2014 amending Annex II to Regulation (EC) 1333/2008 of the Euroepan Parliament and of the Council as regards the use of sulphur dioxide -sulphites (E220-228) in aromatised wine-based products. TEXT with EEA relevance', 'Komisijos reglamentas (ES) 59/2014, 2014 m. sausio 23 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl sieros dioksido ir sulfitų (E220–228) naudojimo aromatizuotuose vyno pagrindu pagamintuose produktuose. Tekstas svarbus EEE', '(EU) No 0059/2014', NULL, NULL, NULL, 'L 21', '9');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (329212, 316516, 'Commission Regulation (EU) No 1093/2014 of 16/10/2014 amending and correcting Annex II of Regulation (EC) 1333/2008 of European Parliament and of the Council as regards the use of certain colours in flavoured ripened cheese. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1093/2014 2014 m. spalio 16 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II priedas dėl tam tikrų dažiklių naudojimo aromatizuotame brandintame sūryje. Tekstas svarbus EEE.', '(EU) No 1093/2014', NULL, NULL, NULL, 'L 299', '22');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (329212, 316636, 'Commission Regulation (EU) 2015/647 of 24/04/2015 amending and correcting Annexes II and III to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/647, 2015 m. balandžio 24 d., kuriuo iš dalies keičiami ir taisomi Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II ir III priedai dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 2015/0647', NULL, NULL, NULL, '107', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (329212, 1764184, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (329212, 2684840, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, scraped_at, translated_at) VALUES (330859, 'E249-250', 'E 249 - 250', 249, 'Nitrites', 'Nitritai', 'Nitrites', 'Nitritai', NULL, NULL, NULL, TRUE, NULL, 'POL-FAD-IMPORT-3057', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', '2026-04-07 08:29:56', '2026-04-07 12:05:56');
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (330859, '315802', '8.3.1', 'Non-heat-treated processed meat', 'Termiškai neapdoroti perdirbti mėsos produktai', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'Period of application: until 9 October 2025', 'Taikymo laikotarpis: iki 2025 m. spalio 9 d.', '7', 'Maximum amount that may be added during the manufacturing, expressed as NaNO2 or NaNO3', 'Didžiausias kiekis, kurį galima pridėti gamybos proceso metu, išreikštas kaip NaNO2 arba NaNO3', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (330859, '315826', '8.3.4.3', 'Other traditional and traditionally cured products (including immersion and dry cured processes used in combination or where nitrite and/or nitrate is included in a compound product or where the curing solution is injected into the product prior to cooking)', 'Kiti tradiciniai ir tradiciškai vytinti produktai (įskaitant mirkymo ir sausojo vytinimo procesus, naudojamus kartu, arba kai nitritas ir (arba) nitratas įtraukiamas į sudėtinį produktą, arba kai vytinimo tirpalas įšvirkščiamas į produktą prieš terminį apdorojimą)', 'FAD_RT_ML', '50', 'FAD_RU_MGK', 'only Rohschinken, trocken-/nassgepökelt and similar products: Dry curing and immersion curing used in combination (without injection of curing solution). Curing time depending on the shape and weight of meat pieces for approximately 14 to 35 days followed by stabilisation/ maturation Period of application: until 9 October 2025', 'tik Rohschinken, trocken-/nassgepökelt ir panašūs produktai: sauso ir drėgno rauginimo derinys (be rauginimo tirpalo injekcijų). Rauginimo trukmė priklauso nuo mėsos gabalų formos ir svorio – apytiksliai 14–35 dienos, po to vyksta stabilizavimas ir brendimas. Taikymo laikotarpis: iki 2025 m. spalio 9 d.', '7', 'Maximum amount that may be added during the manufacturing, expressed as NaNO2 or NaNO3', 'Didžiausias kiekis, kurį galima pridėti gamybos proceso metu, išreikštas kaip NaNO2 arba NaNO3', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (330859, '315806', '8.3.2', 'Heat-treated processed meat', 'Termiškai apdorota perdirbta mėsa', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'except sterilised meat products (Fo > 3,00) Period of application: until 9 October 2025', 'išskyrus sterilizuotus mėsos produktus (Fo > 3,00) Taikymo laikotarpis: iki 2025 m. spalio 9 d.', '7', 'Maximum amount that may be added during the manufacturing, expressed as NaNO2 or NaNO3', 'Didžiausias kiekis, kurį galima pridėti gamybos proceso metu, išreikštas kaip NaNO2 arba NaNO3', 316926);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (330859, '315818', '8.3.4.1', 'Traditional immersion cured products (meat products cured by immersion in a curing solution containing nitrites and/or nitrates, salt and other components)', 'Tradiciniai produktai, vytinti panardinant (mėsos produktai, vytinti panardinant į vytinimo tirpalą, kurio sudėtyje yra nitritų ir (arba) nitratų, druskos ir kitų komponentų)', 'FAD_RT_ML', '175', 'FAD_RU_MGK', 'only Wiltshire bacon and similar products: Meat is injected with curing solution followed by immersion curing for 3 to 10 days. The immersion brine solution also includes microbiological starter cultures Period of application: until 9 October 2025', 'tik Wiltshire bacon ir panašūs produktai: mėsa injekuojama rauginimo tirpalu, po to rauginama panardinant 3–10 dienų. Panardinimo rauginimo tirpale taip pat naudojamos mikrobiologinės starterinės kultūros. Taikymo laikotarpis: iki 2025 m. spalio 9 d.', '39', 'Maximum residual amount, residue level at the end of the production process, expressed as NaNO2 or NaNO3', 'Maksimalus likutinis kiekis, likučio lygis gamybos proceso pabaigoje, išreikštas kaip NaNO2 arba NaNO3', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (330859, '315822', '8.3.4.2', 'Traditional dry-cured products (dry curing process involves dry application of curing mixture containing nitrites and/or nitrates, salt and other components to the surface of the meat followed by a period of stabilisation/maturation)', 'Tradiciniai sausai vytinti produktai (sausojo vytinimo procesas apima sauso vytinimo mišinio, kurio sudėtyje yra nitritų ir (arba) nitratų, druskos ir kitų komponentų, nanešimą ant mėsos paviršiaus, po kurio seka stabilizavimosi ir (arba) brandinimo laikotarpis)', 'FAD_RT_ML', '175', 'FAD_RU_MGK', 'only dry cured bacon and similar products: Dry curing followed by maturation for at least 4 days Period of application: until 9 October 2025', 'tik sausai vytinta šoninė ir panašūs produktai: sausas vytinimas, po kurio brandinamas ne mažiau kaip 4 dienas. Taikymo laikotarpis: iki 2025 m. spalio 9 d.', '39', 'Maximum residual amount, residue level at the end of the production process, expressed as NaNO2 or NaNO3', 'Maksimalus likutinis kiekis, likučio lygis gamybos proceso pabaigoje, išreikštas kaip NaNO2 arba NaNO3', 316636);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (330859, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only lomo de cerdo adobado, pincho moruno, careta de cerdo adobada, costilla de cerdo adobada, Kasseler, Bräte, Surfleisch, toorvorst, šašlõkk, ahjupraad, kiełbasa surowa biała, kiełbasa surowa metka, tatar wołowy (danie tatarskie) and golonka peklowana Period of application: until 9 October 2025', 'tik lomo de cerdo adobado, pincho moruno, careta de cerdo adobada, costilla de cerdo adobada, Kasseler, Bräte, Surfleisch, toorvorst, šašlõkk, ahjupraad, kiełbasa surowa biała, kiełbasa surowa metka, tatar wołowy (danie tatarskie) ir golonka peklowana Taikymo laikotarpis: iki 2025 m. spalio 9 d.', '7', 'Maximum amount that may be added during the manufacturing, expressed as NaNO2 or NaNO3', 'Didžiausias kiekis, kurį galima pridėti gamybos proceso metu, išreikštas kaip NaNO2 arba NaNO3', 316776);
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (330859, 316526, 'Commission Regulation (EU) No 1129/2011 of 11 November 2011 amending Annex II to Regulation EC No 1333/2008 of the European Parliament and of the Council by establishing a Union list of food Additives . TEXT with EEA relevance.', 'Komisijos reglamentas (ES) Nr. 1129/2011 2011 m. lapkričio 11 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas nustatant Sąjungos maisto priedų sąrašą. Tekstas svarbus EEE.', '(EU) No 1129/2011', NULL, NULL, NULL, 'L295', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (330859, 316926, 'Commission Regulation (EU) 438/2013 of 13/05/2013 amending and correcting Annex II to Regulation (EU) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 438/2013, 2013 m. gegužės 13 d., kuriuo iš dalies keičiamas ir taisomas Europos Parlamento ir Tarybos reglamento (ES) 1333/2008 II priedas dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 438/2013', 'http://eur-lex.europa.eu/LexUriServ/LexUriServ.do?uri=OJ:L:2013:129:0028:0033:EN:PDF', NULL, NULL, 'L129', '28');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (330859, 316636, 'Commission Regulation (EU) 2015/647 of 24/04/2015 amending and correcting Annexes II and III to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of certain food addtives. TEXT with EEA relevance.', 'Komisijos reglamentas (ES) 2015/647, 2015 m. balandžio 24 d., kuriuo iš dalies keičiami ir taisomi Europos Parlamento ir Tarybos reglamento (EB) 1333/2008 II ir III priedai dėl tam tikrų maisto priedų naudojimo. Tekstas svarbus EEE', '(EU) No 2015/0647', NULL, NULL, NULL, '107', '1');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (330859, 316776, 'COMMISSION REGULATION (EU) 2017/839 of 17/05/2017 amending Annex II to Regulation (EC) 1333/2008 of the European Parliament and of the Council as regards the use of nitrites (E249-250) in "golonka peklowana". TEXT with EEA relevance.', 'KOMISIJOS REGLAMENTAS (ES) 2017/839 2017 m. gegužės 17 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl nitritų (E 249-250) naudojimo „golonka peklowana". Tekstas svarbus EEE.', '(EU) No 2017/0839', NULL, NULL, NULL, '125', '7');
INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (330859, 1667175, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additives (id, e_number, e_number_display, e_number_sort, display_name_en, display_name_lt, identifying_name_en, identifying_name_lt, synonyms_en, synonyms_lt, ins_number, is_group, member_of_group, policy_item_code, source_url, scraped_at, translated_at) VALUES (2815922, 'E251-252', 'E 251 - 252', 251, 'Nitrates', 'Nitratai', 'Nitrates', 'Nitratai', NULL, NULL, NULL, TRUE, NULL, 'POL-FAD-IMPORT-3060', 'https://ec.europa.eu/food/food-feed-portal/screen/food-additives/search', '2026-04-07 08:31:26', '2026-04-07 12:05:56');
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315558', '1.7.2', 'ripened cheese', 'subrandintas sūris', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only hard, semi-hard and semi-soft cheese. Period of application: until 9 October 2026', 'tik kieti, pusiau kieti ir pusiau minkšti sūriai. Taikymo laikotarpis: iki 2026 m. spalio 9 d.', '30', 'In the cheese milk or equivalent level if added after removal of whey and addition of water', 'Sūrio piene arba lygiavertis kiekis, jei pridedama po išrūgų pašalinimo ir vandens įpylimo', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315566', '1.7.4', 'whey cheese', 'išrūgų sūris', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only cheese milk of hard, semi-hard and semi-soft cheese Period of application: until 9 October 2026', 'tik kietojo, pusiau kietojo ir pusiau minkštojo sūrio gamybai skirtas pienas Taikymo laikotarpis: iki 2026 m. spalio 9 d.', '30', 'In the cheese milk or equivalent level if added after removal of whey and addition of water', 'Sūrio piene arba lygiavertis kiekis, jei pridedama po išrūgų pašalinimo ir vandens įpylimo', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315574', '1.7.6', 'cheese products (excluding products falling in category 16)', 'sūrio produktai (išskyrus produktus, priklausančius 16 kategorijai)', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only hard, semi-hard and semi-soft ripened products Period of application: until 9 October 2026', 'tik kieti, pusiau kieti ir pusiau minkšti subrandinti produktai. Taikymo laikotarpis: iki 2026 m. spalio 9 d.', '30', 'In the cheese milk or equivalent level if added after removal of whey and addition of water', 'Sūrio piene arba lygiavertis kiekis, jei pridedama po išrūgų pašalinimo ir vandens įpylimo', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315802', '8.3.1', 'Non-heat-treated processed meat', 'Termiškai neapdoroti perdirbti mėsos produktai', 'FAD_RT_ML', '110', 'FAD_RU_MGK', 'only large bacon primals and dry sausages without nitrites added Period of application: from 9 October 2025’;', 'tik stambūs bekono gabalai ir sausos dešros be pridėtų nitritų Taikymo laikotarpis: nuo 2025 m. spalio 9 d.'';', '7', 'Maximum amount that may be added during the manufacturing, expressed as NaNO2 or NaNO3', 'Didžiausias kiekis, kurį galima pridėti gamybos proceso metu, išreikštas kaip NaNO2 arba NaNO3', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '270', 'FAD_RU_MGK', 'only pickled herring and sprat Period of application: from 9 October 2025’;', 'tik marinuotos silkės ir brisliai Taikymo laikotarpis: nuo 2025 m. spalio 9 d.'';', NULL, NULL, NULL, 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315818', '8.3.4.1', 'Traditional immersion cured products (meat products cured by immersion in a curing solution containing nitrites and/or nitrates, salt and other components)', 'Tradiciniai produktai, vytinti panardinant (mėsos produktai, vytinti panardinant į vytinimo tirpalą, kurio sudėtyje yra nitritų ir (arba) nitratų, druskos ir kitų komponentų)', 'FAD_RT_ML', '250', 'FAD_RU_MGK', 'only Wiltshire bacon and similar products: Meat is injected with curing solution followed by immersion curing for 3 to 10 days. The immersion brine solution also includes microbiological starter cultures Period of application: until 9 October 2025', 'tik Wiltshire bacon ir panašūs produktai: mėsa injekuojama rauginimo tirpalu, po to rauginama panardinant 3–10 dienų. Panardinimo rauginimo tirpale taip pat naudojamos mikrobiologinės starterinės kultūros. Taikymo laikotarpis: iki 2025 m. spalio 9 d.', '7', 'Maximum amount that may be added during the manufacturing, expressed as NaNO2 or NaNO3', 'Didžiausias kiekis, kurį galima pridėti gamybos proceso metu, išreikštas kaip NaNO2 arba NaNO3', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315822', '8.3.4.2', 'Traditional dry-cured products (dry curing process involves dry application of curing mixture containing nitrites and/or nitrates, salt and other components to the surface of the meat followed by a period of stabilisation/maturation)', 'Tradiciniai sausai vytinti produktai (sausojo vytinimo procesas apima sauso vytinimo mišinio, kurio sudėtyje yra nitritų ir (arba) nitratų, druskos ir kitų komponentų, nanešimą ant mėsos paviršiaus, po kurio seka stabilizavimosi ir (arba) brandinimo laikotarpis)', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only dry cured bacon and similar products: Dry curing followed by maturation for at least 4 days Period of application: from 9 October 2025', 'tik sausai vytinta šoninė ir panašūs produktai: sausas vytinimas, po kurio brandinamas ne mažiau kaip 4 dienas. Taikymo laikotarpis: nuo 2025 m. spalio 9 d.', '39', 'Maximum residual amount, residue level at the end of the production process, expressed as NaNO2 or NaNO3', 'Maksimalus likutinis kiekis, likučio lygis gamybos proceso pabaigoje, išreikštas kaip NaNO2 arba NaNO3', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315826', '8.3.4.3', 'Other traditional and traditionally cured products (including immersion and dry cured processes used in combination or where nitrite and/or nitrate is included in a compound product or where the curing solution is injected into the product prior to cooking)', 'Kiti tradiciniai ir tradiciškai vytinti produktai (įskaitant mirkymo ir sausojo vytinimo procesus, naudojamus kartu, arba kai nitritas ir (arba) nitratas įtraukiamas į sudėtinį produktą, arba kai vytinimo tirpalas įšvirkščiamas į produktą prieš terminį apdorojimą)', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only Rohschinken, trocken-/nassgepökelt and similar products: Dry curing and immersion curing used in combination (without injection of curing solution). Curing time depending on the shape and weight of meat pieces for approximately 14 to 35 days followed by stabilisation/ maturation Period of application: from 9 October 2025', 'tik Rohschinken, trocken-/nassgepökelt ir panašūs produktai: sauso ir drėgno rauginimo derinys (be rauginimo tirpalo injekcijų). Rauginimo trukmė priklauso nuo mėsos gabalų formos ir svorio – apytiksliai 14–35 dienos, po to vyksta stabilizavimas ir brendimas. Taikymo laikotarpis: nuo 2025 m. spalio 9 d.', '7', 'Maximum amount that may be added during the manufacturing, expressed as NaNO2 or NaNO3', 'Didžiausias kiekis, kurį galima pridėti gamybos proceso metu, išreikštas kaip NaNO2 arba NaNO3', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2815922, '315582', '1.8', 'Dairy analogues, including beverage whiteners', 'Pieno produktų analogai, įskaitant gėrimų skiediklius', 'FAD_RT_ML', '150', 'FAD_RU_MGK', 'only dairy-based cheese analogue Period of application: until 9 October 2025', 'tik pieno pagrindu pagaminti sūrio analogai Taikymo laikotarpis: iki 2025 m. spalio 9 d.', NULL, NULL, NULL, NULL);
