INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (332266, '315782', '7.2', 'Fine bakery wares', 'Smulkūs kepiniai', 'FAD_RT_ML', '2000', 'FAD_RU_MGK', 'only prepacked fine bakery wares, (including flour confectionery) with a water activity of more than 0,65', 'tik iš anksto supakuoti smulkūs kepiniai (įskaitant miltiniai konditerijos gaminiai), kurių vandens aktyvumas didesnis nei 0,65', '1', 'The additives may be added individually or in combination', 'Priedai gali būti dedami atskirai arba kartu', 316526);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (332266, '316098', '16', 'Desserts excluding products covered in category 1 3 and 4', 'Desertai, išskyrus produktus, kuriems taikomos kategorijos 1, 3 ir 4', 'FAD_RT_ML', '1000', 'FAD_RU_MGK', 'only Christmas pudding', 'tik kalėdinis pudingas', '1', 'The additives may be added individually or in combination', 'Priedai gali būti dedami atskirai arba kartu', 316526);
