INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (332266, '315770', '7.1', 'Bread and rolls', 'Duona ir bandelės', 'FAD_RT_ML', '3000', 'FAD_RU_MGK', 'only prepacked sliced bread and rye bread', 'tik iš anksto supakuota pjaustyta duona ir ruginė duona', '1', 'The additives may be added individually or in combination', 'Priedai gali būti dedami atskirai arba kartu', 316736);
