INSERT INTO aggregate.eu_additive_legislations (additive_id, eu_legislation_id, title_en, title_lt, text, eurlex_link, publication_date, date_entry_into_force, oj_number, oj_page) VALUES (332266, 316736, 'COMMISSION REGULATION (EU) 2016/683 of 2 May 2016 amending Annex II to Regulation (EC) No 1333/2008 of the European Parliament and of the Council as regards the use of propionic acid — propionates (E 280-283) in tortillas', 'KOMISIJOS REGLAMENTAS (ES) 2016/683 2016 m. gegužės 2 d., kuriuo iš dalies keičiamas Europos Parlamento ir Tarybos reglamento (EB) Nr. 1333/2008 II priedas dėl propiono rūgšties – propionatų (E 280-283) naudojimo tortiljose', '(EU) No 2016/0683', NULL, NULL, NULL, 'L 117', '28');
