INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2885712, '315846', '9.2', 'Processed fish and fishery products including molluscs and crustaceans', 'Perdirbta žuvis ir žuvininkystės produktai, įskaitant moliuskus ir vėžiagyvius', 'FAD_RT_ML', '5000', 'FAD_RU_MGK', 'only fish and crustacean paste and in processed frozen and deep-frozen molluscs and crustaceans', 'tik žuvies ir vėžiagyvių pasta bei perdirbti šaldyti ir giliai šaldyti moliuskai ir vėžiagyviai', '1', 'The additives may be added individually or in combination', 'Priedai gali būti dedami atskirai arba kartu', 316526);
