INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2885712, '315794', '8.2', 'Meat preparations as defined by Regulation (EC) No 853/2004', 'Mėsos pusgaminiai, kaip apibrėžta Reglamente (EB) Nr. 853/2004', 'FAD_RT_ML', '5000', 'FAD_RU_MGK', 'only breakfast sausages: in this product, the meat is minced in such a way so that the muscle and fat tissue are completely dispersed, so that fibre makes an emulsion with the fat, giving the product its typical appearance; Finnish grey salted Christmas ham, burger meat with a minimum vegetable and/ or cereal content of 4 % mixed within the meat, Kasseler, Bräte, Surfleisch, toorvorst, šašlõkk, ahjupraad, Bílá klobása, Vinná klobása, Sváteční klobása, Syrová klobása and frozen vertical rotating meat spits made of sheep, lamb, veal and/or beef treated with liquid seasoning or from poultry meat treated with or without liquid seasoning used alone and/ or combined as well as sliced and/or minced and designed to be roasted by a food business operator and then consumed by the final consumer', 'tik pusryčių dešrelės: šiame produkte mėsa smulkinama taip, kad raumenų ir riebalų audiniai būtų visiškai išsklaidyti, todėl skaidulinės medžiagos sudaro emulsiją su riebalais, suteikdamos produktui būdingą išvaizdą; suomiškas pilkasis sūdytas kalėdinis kumpis, faršo kotletai, kurių minimalus daržovių ir (arba) grūdų kiekis, sumaišytas su mėsa, yra 4 %, Kasseler, Bräte, Surfleisch, toorvorst, šašlõkk, ahjupraad, Bílá klobása, Vinná klobása, Sváteční klobása, Syrová klobása ir užšaldyti vertikaliai besisukantys mėsos iešmai iš avienos, ėrienos, veršienos ir (arba) jautienos, apdirbti skystais prieskoniais, arba iš paukštienos, apdirbtos su skystais prieskoniais arba be jų, naudojami atskirai ir (arba) kartu, taip pat supjaustyti griežinėliais ir (arba) sumalti, skirti kepti maisto verslo operatoriui, o vėliau vartoti galutiniam vartotojui', '1', 'The additives may be added individually or in combination', 'Priedai gali būti dedami atskirai arba kartu', 316806);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2885712, '315770', '7.1', 'Bread and rolls', 'Duona ir bandelės', 'FAD_RT_ML', '20000', 'FAD_RU_MGK', 'only soda bread', 'tik sodos duona', '1', 'The additives may be added individually or in combination', 'Priedai gali būti dedami atskirai arba kartu', 316526);
