INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2885712, '2747784', '14.1.1', 'Water, including natural mineral water as defined in Directive 2009/54/EC and spring water and all other bottled or packed waters', 'Vanduo, įskaitant natūralų mineralinį vandenį, kaip apibrėžta direktyvoje 2009/54/EB, šaltinio vandenį ir visą kitą buteliuose arba kitoje taroje supakuotą vandenį', 'FAD_RT_ML', '500', 'FAD_RU_MGL', 'only prepared table waters', 'tik paruošti staliniai vandenys', NULL, NULL, NULL, NULL);
INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2885712, '2696136', '2.2.1', 'Butter and concentrated butter and butter oil and anhydrous milk fat', 'Sviestas ir koncentruotas sviestas, sviesto aliejus ir bevandenis pieno riebalų produktas', 'FAD_RT_ML', '2000', 'FAD_RU_MGK', 'only soured cream butter', 'tik rūgštintas grietinėlinis sviestas', NULL, NULL, NULL, NULL);
