INSERT INTO aggregate.eu_additive_restrictions (additive_id, food_category_id, food_category_number, food_category_name_en, food_category_name_lt, restriction_type, restriction_value, restriction_unit, restriction_comment_en, restriction_comment_lt, note_number, note_text_en, note_text_lt, legislation_id) VALUES (2692440, '316042', '14.2.1', 'beer and malt beverages', 'alus ir salyklo gėrimai', 'FAD_RT_ML', '70', 'FAD_RU_MGK', 'only alcohol-free beer or with an alcohol content not exceeding 1,2 % vol.; ‘Bière de table/Tafelbier/Table beer’ (original wort content less than 6 %) except for ‘Obergäriges Einfachbier’; beers with a minimum acidity of 30 milli-equivalents expressed as NaOH; Brown beers of the ‘oud bruin’ type’;', 'tik nealkoholinis alus arba alus, kurio alkoholio kiekis neviršija 1,2 % tūrio; „Bière de table/Tafelbier/Table beer" (pradinio salyklo kiekis mažiau nei 6 %), išskyrus „Obergäriges Einfachbier"; alus, kurio minimalus rūgštingumas yra 30 miliekvivalentų, išreikštas kaip NaOH; tamsus alus „oud bruin" tipo', NULL, NULL, NULL, 720370);
